const NEW_QUESTIONS_L6_10 = {
6: [
  {"question":"Set-associative cache 4-way berarti setiap set dapat menampung...","options":["1 cache line","2 cache line","4 cache line","8 cache line"],"answer":2,"difficulty":2,"explanation":"4-way set associative = setiap set punya 4 slot (ways). Satu blok memori bisa dipetakan ke salah satu dari 4 posisi dalam set yang sesuai, fleksibilitas lebih dari direct-mapped tanpa overhead penuh fully associative."},
  {"question":"Pada direct-mapped cache dengan 8 set, blok memori nomor 21 dipetakan ke set nomor...","options":["21","5","3","2"],"answer":1,"difficulty":2,"explanation":"Index set = nomor blok MOD jumlah set = 21 MOD 8 = 5. Direct-mapped menggunakan modulo — blok 5, 13, 21, 29 semuanya bersaing di set yang sama (conflict miss)."},
  {"question":"Write-allocate policy pada cache write-miss berarti...","options":["Data langsung ditulis ke memori utama tanpa mengubah cache","Blok dari memori di-load dulu ke cache baru kemudian ditulis","Write diabaikan jika cache penuh","Data ditulis ke register sementara"],"answer":1,"difficulty":2,"explanation":"Write-allocate (fetch-on-write): saat write-miss, blok yang akan ditulis di-fetch dulu dari memori ke cache, kemudian penulisan dilakukan di cache. Biasanya dipasangkan dengan write-back policy."},
  {"question":"Victim cache ditempatkan antara L1 dan L2 dengan tujuan...","options":["Menyimpan instruksi yang sudah dieksekusi","Menampung blok yang baru saja di-evict dari L1 sebelum ke L2","Menyimpan data yang sering ditulis ke disk","Cache khusus untuk operasi floating point"],"answer":1,"difficulty":3,"explanation":"Victim cache (Jouppi 1990): small fully-associative cache antara L1 dan L2. Blok yang di-evict dari L1 masuk ke victim cache — jika segera diakses lagi (miss di L1 tapi hit di victim cache) latency jauh lebih rendah dari L2 miss."},
  {"question":"Cache thrashing terjadi ketika...","options":["Cache terlalu besar untuk working set program","Program terus-menerus mengakses blok yang saling menggusur di set yang sama","CPU mengakses cache lebih cepat dari spesifikasi","L1 dan L2 cache kehilangan sinkronisasi"],"answer":1,"difficulty":3,"explanation":"Thrashing: dalam direct-mapped atau N-way dengan sedikit ways, jika program mengakses blok yang memetakan ke set sama secara bergantian, mereka terus saling menggusur (conflict miss terus-menerus). Solusi: meningkatkan associativity atau mengubah layout data."},
  {"question":"Inclusive cache policy berarti...","options":["L1 dan L2 tidak boleh menyimpan blok yang sama","L2 hanya menyimpan blok yang tidak ada di L1","Semua blok di L1 pasti ada salinannya di L2","L1 selalu lebih besar dari L2"],"answer":2,"difficulty":3,"explanation":"Inclusive: semua data di L1 dijamin ada di L2. Keuntungan: coherency mudah (invalidate di L2 cukup). Kerugian: kapasitas L2 terbuang untuk duplikasi. Exclusive policy sebaliknya — blok hanya ada di satu level."},
  {"question":"AMAT = Hit Time + Miss Rate × Miss Penalty. Jika hit time 4ns, miss rate 10%, miss penalty 100ns, maka AMAT adalah...","options":["104ns","14ns","40ns","4.1ns"],"answer":1,"difficulty":2,"explanation":"AMAT = 4 + (0.10 × 100) = 4 + 10 = 14ns. Miss penalty 100ns dengan miss rate 10% memberikan kontribusi 10ns, mendominasi hit time 4ns. Formula ini digunakan untuk mengevaluasi efektivitas desain cache."},
  {"question":"Tag field pada alamat cache digunakan untuk...","options":["Menentukan set mana yang dituju","Menentukan byte mana di dalam blok","Memverifikasi apakah blok di cache memang yang dicari","Menentukan algoritma replacement yang dipakai"],"answer":2,"difficulty":2,"explanation":"Alamat dibagi: [Tag | Index | Offset]. Tag dibandingkan dengan tag tersimpan di cache line untuk verifikasi hit/miss. Index menentukan set. Offset menentukan byte dalam blok. Tag check terjadi setiap akses."},
  {"question":"False sharing dalam multiprocessor cache terjadi ketika...","options":["Dua prosesor mengakses variabel yang persis sama","Dua prosesor mengakses variabel berbeda yang berada dalam cache line yang sama","L1 cache tidak konsisten dengan L2 cache","Cache overflow karena data terlalu besar"],"answer":1,"difficulty":3,"explanation":"False sharing: prosesor A dan B mengakses variabel berbeda (X dan Y) dalam satu cache line. Saat A menulis X, cache line di-invalidate di B — B harus fetch ulang padahal Y tidak berubah. Overhead signifikan di program paralel."},
  {"question":"Dirty bit pada write-back cache digunakan untuk...","options":["Menandai blok yang sedang dalam proses prefetch","Menandai blok yang dimodifikasi di cache tapi belum ditulis ke memori","Mendeteksi error parity dalam cache","Menandai cache line yang sudah kadaluarsa"],"answer":1,"difficulty":2,"explanation":"Dirty bit = 1 berarti cache line telah dimodifikasi CPU tapi memori utama belum diupdate. Saat blok di-evict: dirty=1 → write-back ke memori dulu; dirty=0 → buang saja (memori sudah up-to-date)."},
  {"question":"3C model of cache misses terdiri dari...","options":["Cold miss, Conflict miss, Capacity miss","Core miss, Clock miss, Cache miss","Cold miss, Coherence miss, Computation miss","Compulsory miss, CPU miss, Clock miss"],"answer":0,"difficulty":2,"explanation":"3C (Hennessy & Patterson): (1) Compulsory/Cold — akses pertama ke blok, tak bisa dihindari; (2) Capacity — working set > ukuran cache; (3) Conflict — blok saling tabrakan di set sama. Multiprocessor menambah (4) Coherence miss."},
  {"question":"Pada sistem dengan physical address 32-bit, cache 16KB direct-mapped, block size 64B, berapa bit untuk field Index?","options":["6 bit","8 bit","10 bit","4 bit"],"answer":1,"difficulty":3,"explanation":"Jumlah set = 16KB / 64B = 256 set. Bit index = log2(256) = 8 bit. Bit offset = log2(64) = 6 bit. Tag = 32 - 8 - 6 = 18 bit. Pembagian bit ini fundamental untuk desain dan analisis cache."},
  {"question":"Non-temporal store (instruksi MOVNT pada x86) melewati cache karena...","options":["Data tersebut bukan instruksi program","Data hanya ditulis sekali dan tidak akan segera diakses lagi","Operasi tersebut memerlukan akses DMA","Non-temporal store hanya untuk data GPU"],"answer":1,"difficulty":3,"explanation":"Non-temporal store menulis langsung ke memori tanpa mengisi cache. Berguna untuk streaming data besar (video, memcpy) yang tidak akan diakses ulang segera — memasukkan ke cache justru mengotori cache dengan data tidak berguna (cache pollution)."},
  {"question":"Perbedaan I-cache dan D-cache pada Harvard Architecture adalah...","options":["I-cache selalu lebih besar dari D-cache","Keduanya terpisah sehingga fetch instruksi dan akses data bisa terjadi simultan","D-cache hanya untuk operasi write","I-cache tidak menggunakan locality of reference"],"answer":1,"difficulty":2,"explanation":"Harvard architecture memisahkan I-cache dan D-cache agar pipeline dapat fetch instruksi (dari I-cache) sekaligus membaca/menulis data (dari D-cache) dalam cycle yang sama, menghilangkan structural hazard akses memori."},
  {"question":"Multi-level cache L1, L2, L3 dirancang berdasarkan prinsip...","options":["L1 harus menyimpan seluruh program","Ada trade-off kecepatan vs kapasitas — L1 kecil-cepat, L3 besar-lambat","Setiap core wajib punya cache sendiri secara hukum hardware","L3 harus di luar chip CPU"],"answer":1,"difficulty":2,"explanation":"Memory hierarchy: semakin dekat CPU semakin cepat tapi mahal per-bit. L1 (~4 cycle, 32-64KB), L2 (~12 cycle, 256KB-1MB), L3 (~30-40 cycle, 8-64MB). Tujuan: mayoritas akses terpenuhi dari cache cepat, meminimalkan akses DRAM (~200 cycle)."},
  {"question":"Hardware prefetcher memprediksi blok cache yang dibutuhkan berdasarkan...","options":["Prediksi AI dari sistem operasi","Pola akses memori yang terdeteksi seperti stride pattern","Instruksi PREFETCH eksplisit dari programmer saja","Ukuran program yang sedang berjalan"],"answer":1,"difficulty":3,"explanation":"Hardware prefetcher menganalisis pola: (1) Stream prefetcher: akses sequential (array traversal); (2) Stride prefetcher: pola jarak tetap (array 2D); (3) Pointer/indirect prefetcher: linked list. Prefetch tepat mengurangi miss rate secara dramatis tanpa intervensi programmer."},
  {"question":"Algoritma penggantian cache Optimal (Belady's) tidak bisa diimplementasikan di hardware nyata karena...","options":["Terlalu mahal secara hardware","Membutuhkan pengetahuan tentang akses memori di masa depan","Tidak bekerja pada direct-mapped cache","Membutuhkan cache yang sangat besar"],"answer":1,"difficulty":3,"explanation":"Optimal algorithm (Belady 1966) mengganti blok yang tidak akan diakses paling lama di masa depan — memberikan miss rate teoritis minimum. Tidak implementable karena CPU tidak bisa memprediksi masa depan. Digunakan sebagai benchmark pembanding untuk algoritma praktis (LRU, FIFO, Random)."},
  {"question":"Pseudo-LRU (PLRU) digunakan sebagai pengganti LRU murni pada cache dengan associativity tinggi karena...","options":["PLRU lebih akurat dari LRU","LRU murni membutuhkan hardware counter per cache line yang terlalu mahal","PLRU lebih cepat membaca data","LRU tidak bekerja pada cache dengan lebih dari 4 way"],"answer":1,"difficulty":3,"explanation":"LRU murni pada N-way cache membutuhkan log2(N!) bit per set untuk melacak urutan akses semua N ways — sangat mahal untuk 8-way atau 16-way. PLRU menggunakan bit tree (N-1 bit per set) untuk aproximasi LRU yang cukup baik dengan hardware minimal."},
  {"question":"Fenomena cold start miss (compulsory miss) pada cache tidak dapat dihilangkan sepenuhnya karena...","options":["Cache selalu penuh saat program mulai","Setiap blok data harus diakses setidaknya sekali pertama kali dan pasti miss","Program tidak bisa memprediksi data yang dibutuhkan","OS tidak mengizinkan prefetch sebelum program mulai"],"answer":1,"difficulty":2,"explanation":"Compulsory/cold miss: akses pertama kali ke setiap blok pasti miss karena blok belum pernah di-load ke cache. Tidak bisa dihilangkan — hanya bisa dikurangi dengan prefetching (membawa blok sebelum dibutuhkan) atau larger cache line (lebih banyak data per miss)."},
  {"question":"Write-back cache meningkatkan performa dibanding write-through karena...","options":["Write-back tidak memerlukan dirty bit","Write ke memori utama dilakukan sekaligus saat eviction bukan setiap write","Write-back cache lebih besar kapasitasnya","Write-through lebih lambat karena harus membaca sebelum menulis"],"answer":1,"difficulty":2,"explanation":"Write-through: setiap write ke cache juga langsung menulis ke memori — bandwidth memori tinggi. Write-back: tulis hanya ke cache, ke memori hanya saat eviction — mengurangi traffic memori drastis. Jika blok ditulis 100x sebelum di-evict, write-back hanya 1 kali ke memori vs write-through 100 kali."}
],
7: [
  {"question":"SRAM menggunakan flip-flop untuk menyimpan data. Konsekuensinya adalah...","options":["SRAM perlu refresh periodik seperti DRAM","SRAM lebih cepat tapi membutuhkan lebih banyak transistor per bit","SRAM lebih murah per bit dari DRAM","SRAM tidak bisa digunakan sebagai cache"],"answer":1,"difficulty":2,"explanation":"SRAM: 6 transistor per bit (flip-flop bistable) → lebih besar, mahal, tapi tidak butuh refresh dan akses sangat cepat (~1ns). DRAM: 1 transistor + 1 kapasitor per bit → padat, murah, tapi butuh refresh setiap ~64ms karena kapasitor bocor."},
  {"question":"Burst mode SDRAM (Synchronous DRAM) berarti...","options":["SDRAM bisa membaca dan menulis sekaligus","Setelah akses pertama, SDRAM menghasilkan data berikutnya secara sequential dengan kecepatan penuh","SDRAM menggunakan clock burst untuk meningkatkan voltage","Mode di mana seluruh memory diakses sekaligus"],"answer":1,"difficulty":2,"explanation":"Burst mode: CPU mengakses alamat awal, SDRAM secara otomatis menyediakan N byte berikutnya sesuai cache line size tanpa perlu address baru. Sangat efisien untuk sequential access (fetch instruksi, DMA). SDRAM sinkron dengan clock CPU sehingga timing lebih presisi dari DRAM asinkron."},
  {"question":"ECC (Error Correcting Code) memory menggunakan kode Hamming untuk...","options":["Mengenkripsi data agar aman dari serangan","Mendeteksi dan memperbaiki single-bit error, mendeteksi double-bit error","Mengompresi data agar muat lebih banyak","Mempercepat akses memori dengan prediksi"],"answer":1,"difficulty":2,"explanation":"ECC dengan Hamming code: menambah bit paritas redundan (untuk 64-bit data perlu 8 bit parity = 72-bit ECC). Single Error Correction, Double Error Detection (SECDED). Digunakan di server dan workstation kritis — single bit flip dari cosmic ray bisa menyebabkan crash atau korupsi data tanpa ECC."},
  {"question":"DDR5 RAM memiliki keunggulan dibanding DDR4 dalam hal...","options":["Konsumsi daya yang lebih tinggi untuk kecepatan lebih","Bandwidth lebih tinggi dan voltase operasi lebih rendah (1.1V vs 1.2V)","Kompatibilitas penuh dengan slot DDR4","Kapasitas per chip lebih rendah tapi kecepatan lebih tinggi"],"answer":1,"difficulty":2,"explanation":"DDR5 vs DDR4: bandwidth 2x lipat (DDR5-4800 vs DDR4-3200), voltase turun dari 1.2V ke 1.1V (hemat daya), kapasitas per DIMM meningkat (up to 128GB), dan manajemen power pindah ke modul (on-die ECC). Tidak backward compatible dengan slot DDR4."},
  {"question":"Interleaved memory organisation membagi memori ke beberapa bank untuk...","options":["Meningkatkan kapasitas total memori","Memungkinkan akses paralel ke bank berbeda, meningkatkan throughput efektif","Mengurangi biaya produksi memori","Menyederhanakan rangkaian address decoder"],"answer":1,"difficulty":2,"explanation":"Interleaving: alamat memori didistribusikan ke N bank secara round-robin (alamat 0→bank0, 1→bank1, ..., N→bank0). CPU bisa mulai akses bank1 sementara bank0 masih dalam latency recovery, sehingga throughput efektif meningkat N kali untuk sequential access."},
  {"question":"NAND Flash berbeda dari NOR Flash dalam hal...","options":["NAND lebih cepat untuk random read, NOR lebih cepat untuk sequential","NOR lebih lambat tapi lebih padat, NAND lebih cepat tapi lebih mahal","NAND lebih padat dan lebih cepat untuk sequential write, NOR lebih cepat untuk random read","NAND tidak bisa diprogram ulang sedangkan NOR bisa"],"answer":2,"difficulty":3,"explanation":"NAND: sel disusun seri (padat, murah, cocok mass storage), akses byte tidak langsung, harus baca/tulis per page (~4KB). NOR: sel paralel, bisa execute-in-place (XIP), direct byte access, digunakan untuk firmware/BIOS. SSD dan USB drive menggunakan NAND."},
  {"question":"Row Hammer attack pada DRAM mengeksploitasi...","options":["Kelemahan enkripsi dalam modul memori","Efek fisik di mana akses berulang ke satu row bisa membalik bit di row yang berdekatan","Buffer overflow dalam driver memori","Kelemahan protokol refresh DRAM"],"answer":1,"difficulty":3,"explanation":"Row Hammer (2014): mengakses (hammer) satu DRAM row berulang-ulang dalam waktu singkat menyebabkan kebocoran muatan yang cukup untuk membalik bit di row tetangga. Eksploitasi ini bisa digunakan untuk privilege escalation. Mitigasi: Target Row Refresh (TRR), ECC, dan peningkatan refresh rate."},
  {"question":"Perbedaan antara byte addressing dan word addressing pada memori adalah...","options":["Byte addressing selalu lebih lambat dari word addressing","Pada byte addressing setiap lokasi memori berisi 1 byte, word addressing setiap lokasi berisi 1 word (biasanya 4 byte)","Word addressing tidak kompatibel dengan CPU modern","Byte addressing membutuhkan lebih banyak address line"],"answer":1,"difficulty":2,"explanation":"Byte addressing: setiap alamat menunjuk 1 byte — x86, ARM, dan hampir semua CPU modern menggunakan ini. Word addressing: setiap alamat menunjuk 1 word (32-bit) — beberapa DSP dan RISC awal. Implikasi: byte addressing membutuhkan 2 bit lebih banyak untuk mengalamati memori yang sama dibanding 32-bit word addressing."},
  {"question":"Memory-mapped I/O vs Port-mapped I/O (isolated I/O): perbedaan utamanya adalah...","options":["Memory-mapped I/O hanya untuk memori eksternal","Memory-mapped I/O menggunakan ruang alamat memori untuk device register, port-mapped menggunakan ruang alamat I/O terpisah","Port-mapped I/O tidak memerlukan bus","Memory-mapped I/O lebih lambat karena harus melalui cache"],"answer":1,"difficulty":2,"explanation":"Memory-mapped I/O: device register dipetakan ke ruang alamat memori — bisa diakses dengan instruksi LOAD/STORE biasa, lebih fleksibel, digunakan ARM dan kebanyakan RISC. Port-mapped: instruksi khusus IN/OUT, ruang alamat terpisah (64KB pada x86), proteksi lebih mudah."},
  {"question":"NVDIMM (Non-Volatile DIMM) menggabungkan DRAM dan NAND Flash untuk...","options":["Menggandakan kapasitas memori tanpa menambah slot","Mempertahankan data saat power loss sambil tetap memberikan kecepatan akses mendekati DRAM","Menggantikan SSD dalam sistem server","Memberikan enkripsi hardware untuk data sensitif"],"answer":1,"difficulty":3,"explanation":"NVDIMM: DRAM untuk akses kecepatan tinggi + NAND Flash sebagai backup + supercapacitor. Saat power loss, supercapacitor menyuplai power cukup lama untuk mentransfer seluruh DRAM ke NAND. Saat power kembali, data di-restore ke DRAM. Digunakan untuk persistent memory di server kelas enterprise."},
  {"question":"Fenomena 'memory wall' (Wulf & McKee 1995) menggambarkan masalah...","options":["Kapasitas memori tidak bisa ditingkatkan lagi","Kesenjangan kecepatan antara CPU dan DRAM yang terus melebar setiap tahun","Memori tidak bisa diakses lebih dari satu kali per clock","DRAM tidak bisa berfungsi di suhu tinggi"],"answer":1,"difficulty":3,"explanation":"Memory wall: CPU speed meningkat ~55% per tahun (era 1990-an) sedangkan DRAM latency hanya turun ~7% per tahun. Gap ini terus melebar — CPU modern bisa mengeksekusi ratusan instruksi dalam waktu yang dibutuhkan untuk satu DRAM access. Cache hierarchy adalah respons utama terhadap memory wall problem."},
  {"question":"Timing parameter CL16-18-18-38 pada spesifikasi RAM DDR4 merujuk pada...","options":["Kecepatan MHz dari masing-masing pin RAM","CAS Latency, RAS to CAS Delay, RAS Precharge, dan Row Active Time dalam clock cycles","Jumlah chip dalam satu modul DIMM","Voltase operasi minimum dan maksimum"],"answer":1,"difficulty":3,"explanation":"Timing DDR4: CL (CAS Latency) = clock dari RAS#→data; tRCD (RAS to CAS Delay) = row activation ke column access; tRP (RAS Precharge) = precharge row; tRAS (Row Active Time) = row harus aktif minimum. Angka lebih kecil = lebih cepat. CL16 @ DDR4-3200 = 16/3200MHz×2 = ~10ns latency aktual."},
  {"question":"Kenapa DRAM modern menggunakan double data rate (DDR) alih-alih single data rate?","options":["DDR mengkonsumsi daya setengah dari SDR","DDR mentransfer data pada rising DAN falling edge clock, menggandakan bandwidth tanpa menaikkan frekuensi clock","DDR tidak memerlukan refresh periodik","DDR memiliki kapasitas 2x lebih besar"],"answer":1,"difficulty":2,"explanation":"DDR memanfaatkan kedua tepi (edge) sinyal clock — transfer di rising AND falling edge. DDR4-3200: clock fisik 1600 MHz, tapi 3200 MT/s karena dua transfer per cycle. Bandwidth = 3200 MT/s × 8 bytes (64-bit bus) = 25.6 GB/s per channel. Ini 2x bandwidth dari SDR dengan clock sama."},
  {"question":"Apa fungsi Memory Controller yang terintegrasi langsung di CPU (on-die) dibanding External Memory Controller?","options":["Menambah kapasitas memori yang bisa digunakan","Mengurangi latency akses memori dengan menghilangkan hop melalui northbridge","Memungkinkan penggunaan jenis RAM yang berbeda","Meningkatkan voltase untuk stabilitas"],"answer":1,"difficulty":2,"explanation":"Integrasi memory controller ke dalam CPU die (AMD sejak Athlon 64 2003, Intel sejak Nehalem 2008) menghilangkan bottleneck northbridge. Latensi memori turun signifikan (dari ~80ns menjadi ~50ns) karena tidak perlu traversal FSB (Front Side Bus) eksternal yang menjadi bottleneck bandwidth."},
  {"question":"Storage class memory (SCM) seperti Intel Optane mengisi posisi...","options":["Menggantikan L3 cache di dalam CPU","Di antara DRAM dan SSD dalam hierarki memori, dengan latensi dan persistensi di antara keduanya","Menggantikan NAND Flash sepenuhnya","Di antara L1 dan L2 cache"],"answer":1,"difficulty":3,"explanation":"SCM (menggunakan 3D XPoint/Phase Change Memory): latency ~300ns (vs DRAM ~80ns, SSD ~100μs), byte-addressable seperti DRAM, non-volatile seperti SSD. Mengisi gap besar dalam memory hierarchy. Intel Optane DIMM bisa digunakan sebagai persistent memory atau memory extender untuk workload besar."},
  {"question":"Kenapa kapasitas memori yang bisa diaddress CPU 32-bit terbatas 4GB?","options":["Standar industri membatasi 4GB untuk kompatibilitas","Bus alamat 32-bit hanya bisa merepresentasikan 2^32 = 4.294.967.296 alamat unik","Sistem operasi 32-bit tidak mendukung lebih dari 4GB","Kapasitor DRAM tidak cukup besar untuk 4GB+"],"answer":1,"difficulty":2,"explanation":"Address space = 2^(jumlah bit alamat). CPU 32-bit: 2^32 = ~4.29 miliar alamat unik. Jika setiap alamat menunjuk 1 byte: maksimum 4GB addressable. PAE (Physical Address Extension) bisa memperluas ini ke 64GB dengan trik page table, tapi tiap proses tetap terbatas 4GB virtual address space."},
  {"question":"Parity bit pada memori dapat mendeteksi error tapi tidak bisa memperbaikinya karena...","options":["Parity bit hanya cukup untuk mengetahui ada error tapi tidak lokasi bit yang salah","Parity bit tidak bekerja pada multi-bit error","Parity bit hanya untuk deteksi error di bus, bukan di chip memori","Parity membutuhkan clock sinkronisasi tambahan"],"answer":0,"difficulty":2,"explanation":"Single parity bit memberikan info 'jumlah bit '1' genap atau ganjil' — hanya bisa membedakan 'ada error' atau 'tidak ada error', tidak bisa menentukan bit mana yang flip untuk dikoreksi. ECC menambahkan cukup bit redundan (multiple parity bit dengan posisi berbeda) sehingga lokasi error bisa dihitung dan dikoreksi."},
  {"question":"LPDDR (Low Power DDR) digunakan di smartphone/laptop tipis dibanding DDR biasa karena...","options":["LPDDR memiliki kapasitas lebih besar","LPDDR beroperasi pada voltase lebih rendah (0.6-1.1V vs 1.2V) dan memiliki fitur power management canggih","LPDDR lebih cepat dari DDR dalam segala kondisi","LPDDR tidak memerlukan refresh periodik"],"answer":1,"difficulty":2,"explanation":"LPDDR (Low Power Double Data Rate): dirancang untuk mobile. Voltase lebih rendah = konsumsi daya lebih kecil. Fitur power management: partial array refresh (hanya refresh area yang aktif), deep power down mode, dll. Trade-off: biasanya di-solder langsung ke PCB (tidak upgradeable) dan bandwidth sedikit di bawah standar DDR."},
  {"question":"Apa yang dimaksud dengan memory rank pada modul DIMM?","options":["Kapasitas total modul dalam GB","Set chip memori yang secara kolektif menyediakan lebar bus data 64-bit","Kecepatan maksimum modul dalam MHz","Jumlah layer PCB dalam modul"],"answer":1,"difficulty":3,"explanation":"Memory rank: sekelompok chip DRAM yang bekerja bersama menyediakan 64-bit data (atau 72-bit untuk ECC). DIMM single-rank: semua chip di satu sisi aktif bersamaan. Dual-rank: dua kelompok chip, hanya satu aktif per akses. Server bisa menggunakan quad-rank RDIMM untuk kapasitas maksimal. Lebih banyak rank = capacity tinggi tapi timing sedikit lebih lambat."},
  {"question":"Teknik 3D stacking (HBM - High Bandwidth Memory) menumpuk chip DRAM vertikal untuk...","options":["Mengurangi kapasitas agar lebih murah","Mendekatkan memori ke GPU die sehingga bandwidth sangat tinggi dan latensi rendah via Through-Silicon Via (TSV)","Meningkatkan voltase operasi untuk kecepatan lebih","Menggantikan kebutuhan cache pada GPU"],"answer":1,"difficulty":3,"explanation":"HBM (AMD Fury, NVIDIA A100): chip DRAM ditumpuk vertikal dan dihubungkan ke GPU die via silicon interposer menggunakan Through-Silicon Via (TSV). Bus sangat lebar (1024-bit per stack vs 256-bit GDDR6). HBM4 mencapai >3.6 TB/s bandwidth — solusi untuk memory bandwidth bottleneck pada AI workload."}
],
8: [
  {"question":"Addressing mode 'register indirect' berbeda dari 'register direct' karena...","options":["Register indirect menggunakan dua register sekaligus","Register indirect menggunakan nilai dalam register sebagai alamat memori, bukan sebagai data langsung","Register indirect lebih lambat karena perlu decode tambahan","Register indirect hanya tersedia pada CISC architecture"],"answer":1,"difficulty":2,"explanation":"Register direct: operand adalah nilai dalam register (mov R1, R2 → R1 = nilai R2). Register indirect: operand adalah data di memori yang alamatnya ada dalam register (mov R1, [R2] → R1 = memori[R2]). Indirect memungkinkan pointer dan array access dengan satu instruksi."},
  {"question":"Relative addressing mode pada branch instruction menggunakan...","options":["Alamat absolut dari target instruksi","Offset (signed) relatif terhadap Program Counter saat ini","Nilai dari stack pointer","Alamat awal segment kode"],"answer":1,"difficulty":2,"explanation":"PC-relative addressing: target = PC + offset. Offset disimpan dalam instruksi (biasanya 8-26 bit signed). Keuntungan: kode position-independent (bisa di-load di alamat mana saja tanpa relinkasi), instruksi lebih pendek karena offset jauh lebih kecil dari alamat absolut. Digunakan oleh hampir semua ISA modern untuk branch."},
  {"question":"Instruksi CALL pada x86 secara otomatis...","options":["Menyimpan semua register ke stack","Menyimpan return address (PC berikutnya) ke stack lalu jump ke fungsi yang dipanggil","Mengalokasikan frame baru di heap","Menginisialisasi base pointer untuk fungsi baru"],"answer":1,"difficulty":2,"explanation":"CALL: (1) PUSH EIP+instruksi_size ke stack (return address), (2) JMP ke alamat fungsi. RET kemudian: POP alamat dari stack ke EIP. Mekanisme ini memungkinkan nested dan recursive call. Stack frame lengkap (local variables, saved registers) diurus oleh function prologue/epilogue, bukan instruksi CALL itu sendiri."},
  {"question":"Perbedaan zero-address (stack) machine dengan three-address machine adalah...","options":["Stack machine lebih cepat karena tidak perlu decode operand","Stack machine mengambil operand implisit dari stack, three-address machine menentukan semua operand secara eksplisit","Three-address machine hanya tersedia di superkomputer","Stack machine tidak bisa melakukan operasi aritmatika"],"answer":1,"difficulty":2,"explanation":"Zero-address (stack): semua operasi pada TOS (Top of Stack). PUSH A; PUSH B; ADD; POP C. Three-address: ADD C, A, B — sumber dan tujuan eksplisit, compiler bisa optimasi lebih bebas. RISC modern menggunakan three-address (register-register). Java bytecode menggunakan stack machine."},
  {"question":"Instruksi format RISC biasanya fixed-length (32-bit) sedangkan CISC (x86) variable-length. Keuntungan fixed-length untuk pipeline adalah...","options":["Fixed-length lebih mudah dikompresi","Instruksi fetch dan decode bisa dilakukan dalam satu cycle karena panjang pasti, menyederhanakan pipeline","Fixed-length lebih hemat memori","Variable-length tidak bisa dieksekusi secara out-of-order"],"answer":1,"difficulty":2,"explanation":"Fixed-length: decoder tahu pasti batas setiap instruksi sebelum di-decode, fetch tepat 32-bit = satu instruksi, decode paralel mudah. Variable-length (x86): decoder harus scan prefix untuk tentukan panjang, bisa 1-15 byte, boundary instruction sulit ditentukan — x86 CPU modern menghabiskan area chip signifikan hanya untuk instruction boundary detection."},
  {"question":"Little-endian vs big-endian dalam konteks ISA: x86 menggunakan little-endian yang berarti...","options":["Byte pertama dalam memori adalah yang paling signifikan","Byte dengan nilai paling kecil disimpan lebih dulu","Byte paling tidak signifikan (LSB) disimpan di alamat memori terkecil","Data disimpan dari kanan ke kiri dalam register"],"answer":2,"difficulty":2,"explanation":"Little-endian (Intel x86, ARM): byte terendah (LSB) di alamat terendah. Nilai 0x12345678 disimpan sebagai: [0x78][0x56][0x34][0x12]. Big-endian (network byte order, SPARC lama): MSB di alamat terendah. Penting saat: network communication, file format, multi-platform data exchange."},
  {"question":"Privilege levels (Ring 0-3) pada x86 ISA digunakan untuk...","options":["Menentukan kecepatan eksekusi instruksi","Memisahkan level kepercayaan: Ring 0 untuk kernel (akses penuh), Ring 3 untuk aplikasi user (akses terbatas)","Mengatur prioritas thread dalam multitasking","Menentukan ukuran maksimum program"],"answer":1,"difficulty":2,"explanation":"x86 protection rings: Ring 0 (kernel mode) — akses semua instruksi dan hardware, Ring 1-2 (jarang digunakan, driver), Ring 3 (user mode) — instruksi privileged dilarang, akses hardware via system call. Transisi Ring 3→Ring 0 hanya melalui INT, SYSCALL, atau exception — diverifikasi hardware, bukan bisa di-bypass software."},
  {"question":"Instruksi NOP (No Operation) sering digunakan dalam program untuk...","options":["Menginisialisasi register ke nilai nol","Pipeline alignment, delay slot filling, dan area placeholder untuk patching","Menandai akhir program","Reset semua flag kondisi ke 0"],"answer":1,"difficulty":2,"explanation":"NOP uses: (1) Delay slot padding (RISC tanpa interlocking): instruksi setelah branch dieksekusi selalu, NOP mengisi jika tidak ada instruksi berguna; (2) Pipeline alignment: menyelaraskan instruksi ke boundary tertentu untuk performa; (3) Code patching: ruang untuk instruksi yang akan diinsert kemudian; (4) Timing loop dalam embedded systems."},
  {"question":"System call (SYSCALL/INT 0x80) adalah mekanisme untuk...","options":["Memanggil fungsi dalam library eksternal","Meminta layanan dari kernel OS dengan aman, berpindah dari Ring 3 ke Ring 0 secara terkontrol","Reset CPU ke kondisi awal","Mengakses instruksi floating point"],"answer":1,"difficulty":2,"explanation":"System call: user program (Ring 3) tidak bisa langsung akses hardware. SYSCALL/INT 0x80 menyebabkan CPU berpindah ke Ring 0 (kernel), mengeksekusi handler spesifik berdasarkan syscall number dalam register, lalu kembali ke Ring 3. Semua akses file, network, memory allocation pada dasarnya melalui system call."},
  {"question":"SIMD instruction (Single Instruction Multiple Data) seperti SSE/AVX pada x86 berguna untuk...","options":["Mengeksekusi multiple thread secara bersamaan","Satu instruksi mengoperasikan multiple data element sekaligus dalam register lebar (128/256/512-bit)","Memberikan instruksi berbeda ke core berbeda","Meningkatkan frekuensi clock secara dinamis"],"answer":1,"difficulty":3,"explanation":"SIMD: SSE2 punya register 128-bit, bisa proses 4 float atau 2 double sekaligus. AVX2: 256-bit, 8 float atau 4 double. AVX-512: 512-bit, 16 float. Digunakan dalam: encoding video (H.264/H.265), machine learning inference, kriptografi, rendering grafis — speedup 4-16x dibanding scalar untuk compute-bound workload."},
  {"question":"Load-use hazard dalam pipeline RISC terjadi ketika...","options":["Instruksi LOAD dan STORE mengakses alamat yang sama","Instruksi setelah LOAD mencoba menggunakan hasil LOAD sebelum data tersedia dari memori","Dua instruksi LOAD dieksekusi bersamaan","Cache miss terjadi saat LOAD"],"answer":1,"difficulty":3,"explanation":"Load-use hazard: instruksi LOAD menulis hasil ke register setelah stage MEM (biasanya cycle ke-4). Instruksi berikutnya yang membaca register tersebut sudah di stage EX cycle ke-3 — terlalu awal. Forwarding tidak bisa membantu (data belum ada). Solusi: load-use stall (1 bubble) atau compiler reorder instruksi untuk fill slot."},
  {"question":"VLIW (Very Long Instruction Word) architecture memindahkan tanggung jawab instruction scheduling ke...","options":["Hardware branch predictor","Compiler saat compile time, bukan hardware saat runtime","Sistem operasi saat program loading","Programmer secara eksplisit dalam assembly"],"answer":1,"difficulty":3,"explanation":"VLIW: satu instruction word sangat panjang (misalnya 256-bit) berisi beberapa operasi independen yang dieksekusi paralel. Hardware tidak perlu hazard detection atau out-of-order — compiler sudah menjamin tidak ada dependency. Sederhana di hardware, sulit di compiler. Intel Itanium (EPIC) adalah contoh komersial yang kurang berhasil."},
  {"question":"Delayed branching pada RISC pipeline awal mengharuskan programmer atau compiler untuk...","options":["Menghindari penggunaan branch sama sekali","Menempatkan instruksi berguna di branch delay slot yang selalu dieksekusi setelah branch","Menambahkan NOP sebelum setiap branch","Menggunakan register khusus untuk menyimpan alamat target branch"],"answer":1,"difficulty":3,"explanation":"Delayed branch (MIPS awal, SPARC): instruksi tepat setelah branch (delay slot) selalu dieksekusi, terlepas branch diambil atau tidak. Compiler mengisi delay slot dengan instruksi yang berguna dalam semua kasus — jika tidak bisa, diisi NOP. Menyembunyikan 1-cycle branch penalty tanpa hardware branch predictor yang mahal."},
  {"question":"ISA register file dengan banyak register (32 register pada RISC) vs sedikit (8 register pada x86-32) memberikan keuntungan...","options":["Lebih banyak register berarti CPU lebih cepat secara keseluruhan","Lebih banyak register memungkinkan compiler menyimpan lebih banyak variabel lokal tanpa akses memori (register allocation lebih baik)","Register file besar mengurangi kebutuhan cache","32 register tidak cukup untuk program kompleks"],"answer":1,"difficulty":2,"explanation":"Register allocation: kompiler berusaha menjaga variabel yang sering digunakan di register (akses ~0 cycle) daripada di stack (akses ~4-200 cycle). Dengan 8 register (x86-32), variabel lebih sering spill ke memori. Dengan 32 register (RISC), lebih banyak variabel bisa di-register sepanjang fungsi — code lebih cepat."},
  {"question":"Memory ordering model 'Total Store Order' (TSO) pada x86 berarti...","options":["Semua akses memori berjalan secara serial tanpa reordering","Store dapat tertunda dalam store buffer tapi semua processor melihat semua store dalam urutan yang sama","Load selalu terjadi sebelum store dalam program yang sama","x86 tidak mengizinkan out-of-order memory access"],"answer":1,"difficulty":3,"explanation":"x86 TSO (Total Store Order): lebih kuat dari relaxed memory model tapi tidak sekuat sequential consistency. Store bisa di-buffer sebelum visible ke prosesor lain (store-load reordering diizinkan), tapi store ordering relatif antar prosesor konsisten. Programmer butuh memory barrier (MFENCE/SFENCE/LFENCE) untuk full ordering."},
  {"question":"Kondisi flag (Zero, Carry, Sign, Overflow) pada x86 di-update setelah operasi aritmatika untuk...","options":["Menentukan kecepatan eksekusi instruksi berikutnya","Memungkinkan conditional branch dan conditional move berdasarkan hasil operasi sebelumnya","Menyimpan carry dari operasi bit shifting","Menandai register yang telah dimodifikasi"],"answer":1,"difficulty":2,"explanation":"EFLAGS (x86): ZF (Zero Flag) = hasil nol; CF (Carry Flag) = carry/borrow unsigned; SF (Sign Flag) = hasil negatif; OF (Overflow Flag) = overflow signed. Instruksi CMP (compare) melakukan SUB tapi hanya update flags. JZ, JNE, JG, JL, dll. membaca flags ini untuk conditional branching."},
  {"question":"Floating point arithmetic menggunakan standar IEEE 754 untuk...","options":["Meningkatkan kecepatan komputasi integer","Merepresentasikan bilangan real dengan presisi terbatas menggunakan format sign-exponent-mantissa","Menggantikan semua operasi integer","Memudahkan konversi antara desimal dan biner"],"answer":1,"difficulty":2,"explanation":"IEEE 754 single precision (32-bit): 1 bit sign, 8 bit exponent (bias 127), 23 bit mantissa. Range: ±1.4×10^-45 to ±3.4×10^38. Double precision (64-bit): 1+11+52 bit. Standar ini menjamin hasil yang konsisten di berbagai platform. Memiliki representasi khusus: ±0, ±∞, NaN (Not a Number)."},
  {"question":"Teknik loop unrolling dalam compiler optimization mengubah loop untuk...","options":["Mengurangi jumlah iterasi dengan menambah kode instruksi dalam loop body","Menjalankan loop pada thread berbeda","Memindahkan loop ke cache khusus","Menghapus kondisi loop dari program"],"answer":0,"difficulty":3,"explanation":"Loop unrolling: meng-expand body loop N kali dalam satu iterasi, mengurangi branch overhead dan membuka peluang SIMD/ILP. For(i=0;i<100;i++) vs unroll 4x: For(i=0;i<100;i+=4){A[i];A[i+1];A[i+2];A[i+3]}. Trade-off: kode lebih besar (instruction cache pressure) vs performa loop lebih tinggi."},
  {"question":"Pada ISA MIPS, instruksi J (Jump) menggunakan 26-bit target address. Cara CPU menghitung alamat penuh 32-bit target adalah...","options":["Zero-extend 26 bit ke 32 bit","4 bit atas PC digabungkan dengan 26 bit target yang di-shift kiri 2 bit","Target di-sign-extend dari 26 ke 32 bit","Tambahkan offset 26 bit ke base register"],"answer":1,"difficulty":3,"explanation":"MIPS J-format: [opcode 6bit][target 26bit]. Alamat penuh = {PC[31:28], target[25:0], 00} — 4 bit atas dari PC dipertahankan (jump dalam region 256MB yang sama), 26 bit dishift kiri 2 (karena instruksi selalu word-aligned, 2 bit bawah selalu 00), total 32 bit. Untuk jump lintas region, gunakan JR (jump register) dengan alamat 32-bit penuh."},
  {"question":"Interrupts berbeda dari exceptions dalam arsitektur CPU karena...","options":["Interrupt lebih cepat diproses dari exception","Interrupt berasal dari device eksternal (asinkron terhadap instruksi), exception berasal dari eksekusi instruksi itu sendiri (sinkron)","Exception tidak bisa ditangani oleh OS","Interrupt hanya terjadi pada operasi I/O"],"answer":1,"difficulty":2,"explanation":"Interrupt (asinkron): sinyal dari hardware eksternal (timer, keyboard, NIC) — terjadi kapanpun, tidak terkait instruksi spesifik. Exception (sinkron): dipicu oleh instruksi itu sendiri — divide by zero, page fault, invalid opcode, system call. Keduanya menyebabkan CPU berpindah ke handler, bedanya di sumber dan timing."}
],
9: [
  {"question":"Pipeline stall (bubble) yang disebabkan oleh data hazard terjadi karena...","options":["CPU kehabisan instruksi untuk dieksekusi","Instruksi berikutnya membutuhkan hasil instruksi sebelumnya yang belum selesai dieksekusi","Dua instruksi mencoba menggunakan bus yang sama","Branch prediction meleset"],"answer":1,"difficulty":2,"explanation":"Data hazard RAW (Read After Write): instruksi I2 butuh output dari I1, tapi I1 belum selesai di stage sebelumnya. Tanpa forwarding: harus stall sampai I1 tulis ke register. Dengan forwarding: hasil dari stage EX/MEM I1 bisa langsung digunakan I2 tanpa tunggu writeback, mengurangi stall."},
  {"question":"Teknik forwarding (data bypassing) mengurangi pipeline stall dengan cara...","options":["Mempercepat clock CPU secara dinamis","Menyalurkan hasil dari stage pipeline yang lebih awal langsung ke stage yang membutuhkan, tanpa tunggu writeback","Menduplikasi unit eksekusi","Memprediksi nilai operand sebelum komputasi selesai"],"answer":1,"difficulty":2,"explanation":"Forwarding: tambahkan multiplexer dan path langsung antara stage. EX-to-EX forwarding: hasil ALU stage N bisa langsung digunakan stage N+1 tanpa tunggu Write Back (2 cycle kemudian). MEM-to-EX forwarding untuk load result. Forwarding menghilangkan sebagian besar data hazard stall kecuali load-use hazard."},
  {"question":"2-bit saturating counter pada branch predictor menyimpan 4 state untuk...","options":["Memprediksi dua branch sekaligus","Mencegah satu misprediction langsung mengubah prediksi, membutuhkan dua misprediction berturut-turut untuk ganti arah","Menyimpan alamat target branch","Menghitung berapa kali branch diambil"],"answer":1,"difficulty":3,"explanation":"2-bit counter states: Strongly Taken, Weakly Taken, Weakly Not-Taken, Strongly Not-Taken. Loop 'if(x) goto top' yang biasanya taken: berada di Strongly Taken. Satu not-taken (akhir loop) → Weakly Taken, tapi prediksi masih Taken. Loop butuh 2 not-taken berturut-turut untuk flip prediksi — ini ideal karena loop biasanya taken hampir setiap kali."},
  {"question":"Tomasulo's Algorithm mengatasi data hazard dan WAW/WAR hazard menggunakan...","options":["Penambahan pipeline stage khusus","Register renaming via reservation stations yang melacak operand dan hasil secara dinamis","Prediksi nilai operand","Duplikasi register file"],"answer":1,"difficulty":3,"explanation":"Tomasulo (IBM 360/91, 1967): reservation station menyimpan instruksi + operand yang belum ready. Saat operand tersedia (via Common Data Bus), instruksi dispatch ke unit eksekusi. Register renaming implisit melalui reservation station tags menghilangkan WAR dan WAW hazard. Dasar dari out-of-order execution modern."},
  {"question":"Precise exception dalam CPU pipelined berarti...","options":["Hanya exception yang bisa diprediksi yang ditangani","CPU dapat memastikan semua instruksi sebelum yang menyebabkan exception sudah selesai, dan instruksi setelahnya dibatalkan dengan benar","Exception terjadi tepat saat instruksi di-fetch","Semua exception diproses dengan latency yang sama"],"answer":1,"difficulty":3,"explanation":"Precise exception: CPU harus bisa 'membekukan' state tepat pada instruksi yang menyebabkan exception. Program counter menunjuk instruksi faulting, semua instruksi sebelumnya sudah committed, instruksi setelahnya belum. Diperlukan untuk: page fault (restart instruksi), debugging, dan interrupt handling yang benar. Reorder Buffer (ROB) memastikan commit in-order."},
  {"question":"Speculative execution menyebabkan kerentanan Spectre karena...","options":["CPU tidak memverifikasi izin akses memori","CPU mengeksekusi instruksi spekulatif yang mungkin melewati batas keamanan, meninggalkan jejak di side channel (cache timing)","Spekulasi membocorkan data ke register yang bisa dibaca proses lain","Out-of-order execution tidak mengikuti privilege level"],"answer":1,"difficulty":3,"explanation":"Spectre: CPU spekulatif mengeksekusi kode di luar bounds check yang belum di-evaluasi. Akses memori spekulatif ke data privileged mengisi cache. Meski instruksi di-squash (karena missprediksi/pelanggaran keamanan), efek cache tidak di-rollback. Attacker mengukur waktu akses cache (Flush+Reload) untuk deduksi data. Patch memerlukan perubahan ISA dan OS."},
  {"question":"Metode pengurangan branch penalty 'branch delay slot' berbeda dari 'branch prediction' karena...","options":["Delay slot lebih akurat dari prediksi","Delay slot always mengeksekusi instruksi setelah branch terlepas branch diambil, prediksi mencoba menebak arah branch","Prediksi menggunakan lebih banyak hardware dari delay slot","Delay slot hanya tersedia untuk conditional branch"],"answer":1,"difficulty":2,"explanation":"Branch delay slot (arsitektur awal RISC): instruksi tepat setelah branch selalu dieksekusi — compiler mengisi dengan instruksi yang berguna dalam semua kasus. Deterministic tapi compiler harus sadar. Branch prediction: hardware menebak arah, mulai fetch spekulatif, squash jika salah. Prediction lebih efektif untuk pipeline dalam tapi memerlukan hardware kompleks."},
  {"question":"Hyper-Threading (SMT — Simultaneous Multi-Threading) pada Intel CPU bekerja dengan cara...","options":["Membagi CPU secara fisik menjadi dua prosesor independen","Menyimpan dua set architectural state (register, PC) dalam satu core fisik untuk mengisi slot pipeline yang idle","Menjalankan dua program pada kecepatan setengahnya masing-masing","Meningkatkan clock speed saat ada dua thread aktif"],"answer":1,"difficulty":3,"explanation":"SMT/HT: satu core fisik punya 2 (atau lebih) set lengkap architectural state (register file, PC, EFLAGS). Dua thread berjalan 'secara bersamaan' — saat thread 1 stall (cache miss, load latency), thread 2 menggunakan execution units yang idle. Resource sharing: ALU, FPU, cache, TLB dibagi. Overhead area chip kecil (~5%) tapi throughput naik 15-30% untuk mixed workload."},
  {"question":"Control hazard pada pipeline RISC sederhana (tanpa prediksi) menyebabkan wasted cycles karena...","options":["Control unit terlalu lambat untuk menghasilkan sinyal kontrol","CPU tidak tahu instruksi mana yang harus di-fetch berikutnya sampai branch di-execute (setelah stage EX)","Memory terlalu lambat untuk fetch instruksi","ALU tidak bisa memproses instruksi branch"],"answer":1,"difficulty":2,"explanation":"Pada RISC 5-stage (IF, ID, EX, MEM, WB): branch decision diketahui di akhir stage EX (cycle ke-3). Sementara itu, 2 instruksi berikutnya sudah di-fetch dan di-decode — harus di-squash jika branch diambil (2-cycle penalty). Static prediction (assume not-taken) mengurangi penalty tapi tidak menghilangkan."},
  {"question":"Microprogrammed control unit menyimpan sinyal kontrol dalam...","options":["Hardware logic gates yang di-hardwire","Read-only memory (control store) sebagai sequence of microinstructions","Register file khusus untuk kontrol","Cache khusus untuk sinyal kontrol"],"answer":1,"difficulty":2,"explanation":"Microprogrammed CU: setiap instruksi mesin dipetakan ke sequence microinstruction dalam control store (ROM). Lebih mudah diimplementasikan dan dimodifikasi (bug fix via microcode update), tapi lebih lambat dari hardwired. x86 CPU modern menggunakan kombinasi: instruksi sederhana (hardwired fast path) + instruksi kompleks (microcode sequencer)."},
  {"question":"Instruction-level parallelism (ILP) dibatasi oleh...","options":["Kecepatan memori cache","True data dependencies (RAW) antar instruksi yang tidak bisa dihilangkan","Ukuran register file","Kecepatan bus data"],"answer":1,"difficulty":3,"explanation":"ILP: eksekusi instruksi-instruksi independen secara paralel. Dibatasi oleh: (1) RAW (true dependency) — tidak bisa dieleminasi, harus tunggu; (2) WAR dan WAW (false dependency) — bisa dihilangkan dengan register renaming; (3) Control dependency (branch); (4) Memory dependency (load-store aliasing). Studi Rau dan Fisher menunjukkan rata-rata ILP program ~3-5."},
  {"question":"Store buffer (store queue) pada CPU out-of-order digunakan untuk...","options":["Menyimpan instruksi store yang menunggu untuk dieksekusi","Menampung hasil store yang sudah dieksekusi speculative tapi belum committed ke cache/memori","Buffer untuk instruksi yang datang dari memory controller","Menyimpan alamat yang sering diakses oleh store"],"answer":1,"difficulty":3,"explanation":"Store buffer: instruksi store yang sudah di-execute di-simpan sementara sambil menunggu commit (instruksi harus retire in-order). Manfaat: (1) Decoupling eksekusi dari cache write, (2) Subsequent load dari alamat sama bisa langsung forward dari store buffer tanpa akses cache (store-to-load forwarding). Di-flush ke cache saat commit."},
  {"question":"Branch Target Buffer (BTB) menyimpan...","options":["Hasil prediksi (taken/not-taken) untuk setiap branch","Alamat target dari instruksi branch yang pernah dieksekusi","Register yang digunakan oleh instruksi branch","History semua branch yang pernah mispredicted"],"answer":1,"difficulty":3,"explanation":"BTB: cache kecil (256-4096 entry) yang memetakan alamat instruksi branch → alamat target. Saat CPU fetch instruksi, jika alamat ada di BTB, langsung fetch dari target (tanpa decode branch dulu). Dikombinasikan dengan predictor (BHT), memungkinkan prediksi penuh dalam satu cycle sebelum instruksi bahkan di-decode."},
  {"question":"Pada ARM Cortex-A series, TrustZone menyediakan...","options":["Virtualisasi hardware untuk beberapa OS","Lingkungan eksekusi terpercaya (Secure World) yang terisolasi dari Normal World via hardware boundary","Proteksi memori berbasis enkripsi untuk setiap proses","Cache partitioning untuk mencegah side-channel attack"],"answer":1,"difficulty":3,"explanation":"ARM TrustZone: CPU bisa beroperasi dalam dua state — Secure World (TEE: Trusted Execution Environment) dan Normal World (Android/Linux). Transisi via monitor mode (EL3). Secure World punya akses ke memori tertentu yang tidak bisa diakses Normal World meski kernel compromised. Digunakan untuk: fingerprint processing, DRM, mobile payment."},
  {"question":"Physical Register File (PRF) architecture berbeda dari architectural register file karena...","options":["PRF lebih kecil dari architectural register file","PRF jauh lebih besar — menyimpan semua in-flight values dari instruksi yang belum commit, mendukung register renaming out-of-order","PRF menggunakan SRAM yang lebih cepat","PRF diakses melalui cache tersendiri"],"answer":1,"difficulty":3,"explanation":"PRF: pool besar register fisik (misalnya 180 register pada Intel Skylake, vs 16 logical register x86-64). Rename table memetakan logical register → physical register. Setiap instruksi yang tulis alokasi physical register baru — menghilangkan WAR/WAW hazard. Physical register di-free saat instruksi yang memegang nilainya retire."},
  {"question":"Scoreboard algorithm pada CDC 6600 mengatasi data hazard dengan cara...","options":["Menambahkan delay slot setelah setiap instruksi","Melacak status setiap functional unit dan register, menahan instruksi jika dependency belum siap","Menduplikasi semua functional unit","Mengeksekusi semua instruksi secara serial"],"answer":1,"difficulty":3,"explanation":"Scoreboard (CDC 6600, 1964): centralized control yang melacak: (1) Functional unit status (busy/free), (2) Instruction status (per stage), (3) Register result status (unit mana yang akan tulis register X). Instruksi stall jika dependency belum ready. Lebih primitif dari Tomasulo tapi tidak rename register — masih bisa stall karena WAR/WAW."},
  {"question":"Reservation Station (RS) pada Tomasulo's Algorithm berbeda dari simple instruction queue karena...","options":["RS bisa menyimpan lebih banyak instruksi","RS menyimpan operand secara inline sehingga instruksi bisa dispatch begitu operand tersedia, tanpa perlu akses register file kembali","RS digunakan hanya untuk floating point operations","RS adalah nama lain untuk reorder buffer"],"answer":1,"difficulty":3,"explanation":"RS: setiap entry menyimpan operand yang sudah tersedia atau tag untuk operand yang belum ready. Saat operand broadcast di Common Data Bus (CDB), semua RS yang menunggu tag tersebut langsung capture nilai — tidak perlu akses register file lagi. Instruksi dispatch ke execution unit segera saat semua operand siap, tanpa koordinasi central scoreboard."},
  {"question":"Prediksi cabang TAGE (Tagged Geometric History Length) unggul dibanding perceptron predictor karena...","options":["TAGE menggunakan neural network yang lebih kompleks","TAGE menggunakan multiple prediction tables dengan history length geometris, menangkap korelasi branch dengan history panjang maupun pendek","TAGE lebih murah dari segi hardware","TAGE tidak memerlukan training"],"answer":1,"difficulty":3,"explanation":"TAGE (Seznec & Michaud 2006): beberapa predictor table dengan history length geometris (L, 2L, 4L, 8L, ...). Provider dengan history terpanjang yang match digunakan. Jika tidak ada provider panjang yang match, fallback ke bimodal. Menangkap korelasi di berbagai granularitas history. MISPB rate < 3% pada SPEC CPU2006 — state-of-art untuk hardware branch prediction."},
  {"question":"Heat dissipation (thermal design power) membatasi frekuensi CPU karena...","options":["Komponen elektronik mencair pada suhu tinggi","Power ∝ C × V² × f — meningkatkan frekuensi secara linear meningkatkan power secara linear, yang menghasilkan panas proporsional","Pendingin tidak bisa berfungsi di frekuensi tinggi","Memori tidak bisa sinkronisasi dengan CPU frekuensi tinggi"],"answer":1,"difficulty":3,"explanation":"Dynamic power = C × V² × f (C = kapasitansi, V = voltase, f = frekuensi). Meningkatkan f 2x → power 2x → suhu 2x (tanpa voltase naik). Dennard Scaling (menurunkan V saat shrink node) mulai gagal ~2005: sulit turunkan voltase lebih jauh tanpa meningkatkan leakage current. Sejak saat itu, industri beralih ke multi-core daripada menaikkan frekuensi single core."},
  {"question":"Reorder Buffer (ROB) memungkinkan CPU out-of-order untuk...","options":["Menjalankan instruksi lebih cepat dari clock cycle","Mengeksekusi instruksi keluar dari urutan program tapi commit hasilnya ke architectural state secara in-order, memastikan precise exception","Menyimpan instruksi yang gagal di-decode","Menggandakan jumlah register yang tersedia"],"answer":1,"difficulty":3,"explanation":"ROB: circular buffer yang menyimpan semua in-flight instruksi dalam program order. Head = instruksi tertua (siap commit), Tail = instruksi terbaru. Instruksi di-execute out-of-order tapi hanya commit (tulis ke architectural state) saat berada di HEAD dan sudah selesai. Jika exception: semua instruksi lebih muda di-squash, state precise pada titik exception."}
],
10: [
  {"question":"Kondisi Bernstein untuk menentukan apakah dua instruksi bisa dieksekusi paralel memeriksa...","options":["Apakah kedua instruksi menggunakan unit eksekusi yang sama","Tidak ada read-write, write-read, atau write-write dependency antara set input/output keduanya","Apakah kedua instruksi memiliki panjang yang sama","Apakah kedua instruksi mengakses cache yang sama"],"answer":1,"difficulty":3,"explanation":"Bernstein conditions (1966): instruksi I1 dan I2 bisa paralel jika: (1) Output(I1) ∩ Input(I2) = ∅ (no RAW), (2) Input(I1) ∩ Output(I2) = ∅ (no WAR), (3) Output(I1) ∩ Output(I2) = ∅ (no WAW). Dasar teoritis untuk compiler parallelization dan hardware out-of-order execution."},
  {"question":"RISC architecture mengurangi Cycles Per Instruction (CPI) dengan cara...","options":["Menggunakan instruksi yang lebih kompleks untuk mengurangi jumlah instruksi","Menyederhanakan instruksi sehingga hampir semua bisa selesai dalam satu cycle pipeline stage","Meningkatkan frekuensi clock CPU","Menggunakan cache yang lebih besar"],"answer":1,"difficulty":2,"explanation":"RISC: instruksi sederhana, format fixed, load-store, banyak register → pipeline stages pendek dan seragam → CPI mendekati 1 (dengan pipeline). CISC: instruksi kompleks bisa butuh banyak cycle → CPI > 1 untuk banyak instruksi. Modern x86 mendekati RISC di level micro-ops (decode CISC → RISC-like micro-ops internal)."},
  {"question":"Amdahl's Law: jika 80% program bisa diparalelkan, speedup maksimal dengan prosesor tak terbatas adalah...","options":["Tidak terbatas","5x","80x","2x"],"answer":1,"difficulty":2,"explanation":"Amdahl: Speedup_max = 1 / (1 - P) di mana P = fraksi yang bisa diparalelkan. P = 0.8: Speedup = 1 / (1 - 0.8) = 1 / 0.2 = 5x. Serial portion 20% menjadi bottleneck. Dengan 10 prosesor: 1 / (0.2 + 0.8/10) = 1/0.28 = 3.57x. Implikasi: bahkan dengan prosesor tak terbatas, serial part membatasi speedup ke 5x."},
  {"question":"NUMA (Non-Uniform Memory Access) terjadi dalam sistem multiprocessor karena...","options":["Semua prosesor berbagi satu chip memori yang sama","Prosesor yang berbeda memiliki latensi berbeda ke bagian memori yang berbeda — memori lokal lebih cepat dari memori remote","NUMA hanya digunakan dalam superkomputer","Prosesor tidak bisa berbagi memori sama sekali dalam NUMA"],"answer":1,"difficulty":2,"explanation":"NUMA: dalam server multi-socket, setiap socket CPU punya memory controller sendiri dan DIMM lokalnya. Akses memori lokal: ~50-80ns. Akses memori di socket lain via QPI/UPI interconnect: ~150-300ns (2-4x lebih lambat). OS NUMA-aware alokasikan memori di node yang sama dengan thread untuk meminimalkan remote access."},
  {"question":"Gustafson's Law (Gustafson-Barsis Law) memberikan pandangan berbeda dari Amdahl dengan argumen bahwa...","options":["Parallelisme tidak memberikan speedup nyata","Ukuran problem yang diselesaikan biasanya meningkat seiring jumlah prosesor, sehingga bagian serial tetap kecil secara relatif","Semua program bisa diparalelkan 100%","Amdahl's Law hanya valid untuk 2 prosesor"],"answer":1,"difficulty":3,"explanation":"Gustafson (1988): Amdahl mengasumsikan problem size tetap. Kenyataannya, lebih banyak prosesor digunakan untuk solve problem LEBIH BESAR dalam waktu yang sama. Serial fraction relatif mengecil. Scaled speedup = N - s(N-1) di mana s = serial fraction, N = prosesor. Lebih optimistis dari Amdahl untuk workload scientific yang scalable."},
  {"question":"Snooping cache coherence protocol bekerja dengan cara...","options":["Central directory mencatat lokasi setiap cache line","Setiap cache memonitor semua transaksi bus untuk mendeteksi jika ada cache lain yang mengakses line yang dimilikinya","Hanya satu prosesor yang bisa memegang cache line pada satu waktu","Cache coherence diserahkan kepada software (OS)"],"answer":1,"difficulty":3,"explanation":"Bus snooping: semua cache terhubung ke shared bus. Setiap cache 'mendengarkan' semua operasi read/write di bus. Jika cache A memegang line X dan melihat cache B menulis ke X di bus → invalidate copy-nya. Sederhana dan efektif untuk jumlah prosesor kecil (<~16). Untuk jumlah besar, bus menjadi bottleneck → gunakan directory protocol."},
  {"question":"Synchronization primitive 'compare-and-swap' (CAS) digunakan dalam lock-free programming karena...","options":["CAS lebih cepat dari mutex dalam semua kondisi","CAS secara atomik memeriksa nilai dan mengupdate hanya jika nilai masih sama dengan expected — memungkinkan algoritma non-blocking","CAS tidak memerlukan hardware khusus","CAS menghilangkan kebutuhan cache coherency"],"answer":1,"difficulty":3,"explanation":"CAS(addr, expected, new): atomik — compare *addr dengan expected, jika sama, set *addr = new dan return true. Jika tidak sama, return false (nilai sudah berubah oleh thread lain). Digunakan untuk: atomic counter, lock-free stack/queue, read-copy-update (RCU). Hardware: x86 CMPXCHG, ARM LDREX/STREX, Java AtomicInteger."},
  {"question":"Data parallelism berbeda dari task parallelism dalam cara kerja berikut...","options":["Data parallelism lebih mudah diimplementasikan","Data parallelism: operasi yang sama diaplikasikan ke banyak data (SIMD/GPU); task parallelism: tugas berbeda dieksekusi secara bersamaan (pipeline, thread pool)","Task parallelism tidak memerlukan sinkronisasi","Data parallelism hanya bekerja pada array"],"answer":1,"difficulty":2,"explanation":"Data parallelism: array[0..N] += scalar — tiap core proses subset data dengan operasi identik. Ideal untuk GPU (ribuan core SIMD). Task parallelism: producer-consumer pipeline, web server (tiap request = task berbeda). Banyak program hybrid — OpenMP mendukung keduanya: parallel sections (task) dan parallel for (data)."},
  {"question":"Memory consistency model Sequential Consistency (SC) mendefinisikan...","options":["Semua akses memori terjadi dalam urutan clock cycle","Hasil eksekusi parallel sama seolah semua operasi semua processor dieksekusi dalam urutan sequential tertentu, dan operasi tiap processor mempertahankan urutan program","SC memerlukan cache yang disabled","Sequential Consistency hanya untuk single-core CPU"],"answer":1,"difficulty":3,"explanation":"SC (Lamport 1979): model paling intuitif — programmer bisa berasumsi ada total order global dari semua operasi memori. Tapi hardware modern (store buffer, out-of-order) melanggar SC untuk performa. x86 menggunakan TSO (Total Store Order) — lebih relaxed. Java/C++ memory model lebih relaxed lagi. Programmer butuh explicit barriers untuk stronger ordering."},
  {"question":"MPI (Message Passing Interface) vs OpenMP: perbedaan fundamental model komputasinya adalah...","options":["MPI hanya untuk superkomputer, OpenMP untuk desktop","MPI: distributed memory (proses berkomunikasi via explicit message), OpenMP: shared memory (thread berbagi memori, sinkronisasi via barrier/lock)","OpenMP lebih cepat dari MPI dalam semua kondisi","MPI tidak bisa digunakan bersamaan dengan OpenMP"],"answer":1,"difficulty":2,"explanation":"MPI: proses-proses independent dengan memori terpisah — komunikasi via MPI_Send/MPI_Recv, MPI_Bcast, dll. Scalable ke ribuan node cluster. OpenMP: thread dalam satu node berbagi address space — parallelisasi mudah dengan pragma, tapi terbatas dalam satu node. Hybrid MPI+OpenMP: MPI antar node, OpenMP dalam node — paling efisien untuk HPC cluster."},
  {"question":"Warp divergence pada GPU CUDA terjadi ketika...","options":["GPU kehabisan memory bandwidth","Thread dalam satu warp mengeksekusi path kode berbeda akibat conditional branch, menyebabkan beberapa thread idle sementara path lain dieksekusi","Dua warp mencoba mengakses memori yang sama","Kernel GPU dipanggil terlalu sering"],"answer":1,"difficulty":3,"explanation":"Warp (NVIDIA): 32 thread yang dieksekusi SIMT (Single Instruction Multiple Thread). Jika ada if-else dalam kernel: GPU mengeksekusi kedua path secara serial (bukan paralel) — thread yang 'salah path' di-mask/disabled. Worst case: 32 thread, 32 path berbeda → 32x serialization. Minimasi divergence adalah kunci optimasi GPU kernel."},
  {"question":"Cache coherency protocol MOESI menambahkan state 'Owned' untuk...","options":["Menandai cache line yang dimiliki oleh OS","Memungkinkan transfer cache line antar prosesor tanpa harus menulis ke memori utama terlebih dahulu","Menandai cache line yang sedang di-prefetch","State untuk cache line yang sedang dienkripsi"],"answer":1,"difficulty":3,"explanation":"MOESI states: M(odified), O(wned), E(xclusive), S(hared), I(nvalid). State O: prosesor punya copy dirty yang harus diberikan ke prosesor lain yang meminta (memori out-of-date), tapi tidak perlu writeback ke memori dulu. O berbeda dari M: copy O boleh ada di prosesor lain (Shared). Mengurangi memory traffic dibanding MESI yang harus writeback sebelum share."},
  {"question":"Vectorization dalam compiler mengkonversi scalar loop menjadi instruksi SIMD ketika...","options":["Loop selalu memiliki jumlah iterasi yang bisa dibagi 4","Tidak ada data dependency antar iterasi loop (loop-carried dependency) dan akses memori bersifat sequential/stride-1","Compiler mendapat hint dari programmer via pragma","Loop hanya mengandung operasi integer"],"answer":1,"difficulty":3,"explanation":"Auto-vectorization: compiler analisis loop untuk: (1) Independence — tiap iterasi tidak bergantung pada iterasi lain; (2) Aligned, contiguous memory access (stride-1 ideal, stride-2 bisa tapi kurang efisien); (3) Tidak ada alias (pointer analysis). Jika semua terpenuhi: scalar loop → SIMD (SSE/AVX). Programmer bisa bantu dengan restrict pointer, aligned_alloc."},
  {"question":"Heterogeneous computing (CPU + GPU + FPGA) dalam satu sistem digunakan karena...","options":["Satu jenis prosesor tidak cukup powerful","Setiap compute unit dioptimalkan untuk jenis workload berbeda — CPU untuk serial/OS, GPU untuk data-parallel, FPGA untuk fixed-function latency-critical","Regulasi hardware mengharuskan penggunaan semua jenis prosesor","GPU lebih murah dari CPU sehingga digunakan untuk task ringan"],"answer":1,"difficulty":3,"explanation":"Heterogeneous: CPU — general purpose, low-latency serial tasks, OS kernel, branch-heavy code. GPU — high throughput data-parallel (ML training, raytracing, physics simulation). FPGA — custom pipeline dengan latensi sangat rendah dan deterministik (network packet processing, HFT trading, SDR). Workload dibagi ke unit paling efisien."},
  {"question":"Transactional Memory (HTM — Hardware Transactional Memory) seperti Intel TSX menyederhanakan synchronization dengan cara...","options":["Menghilangkan kebutuhan cache dalam program paralel","Memungkinkan programmer menandai 'region transaksional' yang dieksekusi atomik — hardware otomatis mendeteksi konflik dan retry","Mempercepat semua operasi memori 2x","Menggantikan semua lock dengan cas operation"],"answer":1,"difficulty":3,"explanation":"HTM: XBEGIN...XEND mendefinisikan transaksi. Hardware melacak read/write set. Jika tidak ada konflik dengan transaksi lain saat commit → sukses atomik. Jika konflik → abort dan retry. Programmer tidak perlu tulis lock/unlock — lebih mudah dan sering lebih cepat dari lock-based karena tidak ada lock contention untuk transaksi yang tidak bertabrakan."},
  {"question":"Flynn's SIMD (Single Instruction Multiple Data) pada level CPU berbeda dari GPU SIMT karena...","options":["SIMD hanya untuk CPU, SIMT hanya untuk GPU","SIMD: semua lane harus mengeksekusi instruksi identik tanpa divergence; SIMT: thread individual dalam warp bisa diverge (tapi dengan serialization penalty)","SIMT lebih cepat dari SIMD dalam semua kondisi","SIMD mendukung floating point, SIMT tidak"],"answer":1,"difficulty":3,"explanation":"SIMD (CPU — SSE/AVX): 4-16 lane strict lockstep, tidak ada notion of divergence — semua lane eksekusi instruksi yang sama pada data berbeda. SIMT (GPU): 32 thread per warp tampak independen dari sudut pandang programmer, tapi hardware eksekusi dalam lockstep — jika diverge, serialisasi terjadi. SIMT lebih programmer-friendly tapi divergence penalty harus dipahami."},
  {"question":"Scalable coherent interconnect (seperti Intel UPI, AMD Infinity Fabric) pada server multi-socket dirancang untuk...","options":["Menggantikan PCIe untuk GPU connection","Menghubungkan multiple CPU socket dengan bandwidth tinggi dan latensi rendah untuk mendukung cache coherency antar socket","Menghubungkan DRAM langsung ke GPU","Menyediakan interface debugging untuk hardware engineer"],"answer":1,"difficulty":3,"explanation":"UPI/Infinity Fabric: point-to-point interconnect antara CPU sockets. Mendukung: (1) Cache coherency antar socket (MESIF protocol messages), (2) Memory access remote (NUMA), (3) Bandwidth tinggi (UPI 3.0: ~41.6 GB/s per direction). Menggantikan FSB (Front Side Bus) yang menjadi bottleneck — setiap CPU punya direct link ke socket lain."},
  {"question":"GPGPU computing menggunakan GPU untuk komputasi umum (bukan grafis) karena GPU memiliki...","options":["Kecepatan clock yang lebih tinggi dari CPU","Ribuan core sederhana yang optimal untuk throughput-oriented workload dengan banyak data paralel","Kapasitas cache yang lebih besar dari CPU","Kemampuan menjalankan sistem operasi sendiri"],"answer":1,"difficulty":2,"explanation":"GPU vs CPU arsitektur filosofi berbeda: CPU — sedikit core (8-64) yang sangat powerful, optimasi untuk single-thread latency, banyak cache. GPU — ribuan core sederhana (4000-16000 CUDA cores), throughput-oriented, lebih sedikit cache per core, high-bandwidth memory (HBM). Ideal untuk: matrix multiplication (ML), Monte Carlo simulation, FFT, rendering."},
  {"question":"Load balancing dalam sistem multiprocessor bertujuan untuk...","options":["Menyeimbangkan voltase antar prosesor","Mendistribusikan workload secara merata antar prosesor sehingga tidak ada yang idle sementara yang lain overloaded","Mengoptimalkan penggunaan cache di setiap prosesor","Memastikan semua prosesor mengakses memori dengan kecepatan yang sama"],"answer":1,"difficulty":2,"explanation":"Load imbalance: jika P1 dapat 90% pekerjaan dan P2 hanya 10%, total waktu = waktu P1 (P2 idle menunggu). Efisiensi turun drastis. Solusi: (1) Static: bagi tugas merata dari awal (cocok jika beban per tugas seragam); (2) Dynamic: work stealing (thread idle mencuri task dari thread sibuk — digunakan Java ForkJoin, OpenMP dynamic schedule). Dynamic lebih adaptif tapi overhead lebih besar."},
  {"question":"Konsep 'embarrassingly parallel' (pleasingly parallel) merujuk pada masalah yang...","options":["Sangat sulit untuk diparalelkan","Bisa dibagi menjadi submasalah independen tanpa komunikasi antar prosesor, sehingga efisiensi paralel mendekati 100%","Memerlukan sinkronisasi setiap cycle","Hanya bisa dijalankan pada GPU"],"answer":1,"difficulty":2,"explanation":"Embarrassingly parallel: setiap sub-task benar-benar independent — tidak ada shared state, tidak ada komunikasi. Contoh: rendering frame video (tiap frame independent), Monte Carlo simulation (tiap sample independent), brute force password cracking, parameter sweep dalam eksperimen scientific. Speedup linier dengan jumlah prosesor — Amdahl's s≈0, speedup ≈ N."}
]
};

// ============================================================================
// DATA DARI UPDATE_QUIZZES.JS (Level 11-14)
// Catatan: level6_new dari update_quizzes.js diganti dgn versi l6_10 yang lebih lengkap.
// ============================================================================
const NEW_QUESTIONS_L11_14 = {
11: [
  {"question":"Saat memasang CPU ke socket LGA (Land Grid Array) seperti Intel LGA1700, langkah kritis yang harus diperhatikan adalah...","options":["Mengoles thermal paste di socket terlebih dahulu","Memastikan alignment segitiga/notch di CPU dan socket cocok sebelum menurunkan load plate","Mendorong CPU dengan tekanan kuat agar pin-pin socket menancap","Memanaskan CPU terlebih dahulu agar lebih mudah masuk"],"answer":1,"difficulty":2,"explanation":"LGA socket: pin ada di socket (motherboard), bukan di CPU. Tanda segitiga di sudut CPU harus sejajar dengan tanda di socket. Letakkan CPU secara vertikal tanpa tekanan horizontal — gravitasi sudah cukup. Kunci load plate perlahan. Tekanan berlebih atau misalignment bisa membengkokkan pin socket yang sangat mahal untuk diperbaiki."},
  {"question":"Perbedaan antara socket AMD AM5 dan Intel LGA1700 dalam hal pin location adalah...","options":["AM5 menggunakan sistem ZIF (Zero Insertion Force) dengan pin di CPU, LGA1700 dengan pin di socket","AM5 dan LGA1700 keduanya memiliki pin di motherboard","AM5 memiliki pin di socket, LGA1700 memiliki pin di CPU","AM5 tidak menggunakan pin — menggunakan koneksi wireless"],"answer":0,"difficulty":2,"explanation":"AMD AM5: PGA (Pin Grid Array) — pin ada di CPU, socket AM5 adalah ZIF (Zero Insertion Force). Letakkan CPU, turunkan tuas, selesai. Intel LGA1700: LGA — pin ada di socket motherboard, CPU tidak punya pin (hanya pad). Perbedaan ini penting: jika pin CPU AMD bengkok, lebih mudah diperbaiki daripada pin socket LGA yang tertanam di motherboard."},
  {"question":"Saat memasang RAM DDR5 di motherboard dual-channel, untuk memaksimalkan bandwidth sebaiknya...","options":["Pasang di slot A1 dan A2 yang bersebelahan","Pasang di slot yang direkomendasikan manual (biasanya slot 2 dan 4, atau A2 dan B2) untuk dual-channel mode","Pasang di slot manapun karena CPU otomatis mengaktifkan dual-channel","Isi semua 4 slot meskipun hanya punya 2 keping RAM"],"answer":1,"difficulty":2,"explanation":"Dual-channel: dua modul RAM bekerja paralel, bandwidth 2x lipat. Slot yang tepat bervariasi per motherboard (selalu cek manual) — biasanya slot 2 dan 4 (melewati slot 1 dan 3). Jika salah slot, sistem tetap boot tapi hanya single-channel (setengah bandwidth). AMD EXPO/Intel XMP juga perlu diaktifkan di BIOS untuk mencapai kecepatan rated."},
  {"question":"Thermal paste yang berlebihan saat dipasang di CPU dapat menyebabkan...","options":["Pendinginan lebih baik karena lebih banyak pasta","Pasta meluber ke komponen sekitar seperti kapasitor atau soket RAM, berpotensi short circuit","CPU tidak bisa terdeteksi karena terselimuti pasta","Tidak ada efek negatif — kelebihan pasta otomatis menekan keluar"],"answer":1,"difficulty":2,"explanation":"Thermal paste optimal: selapis tipis merata (ukuran biji buncis atau pea-size di tengah). Berlebihan: saat cooler dipasang dan ditekan, pasta meluber keluar, bisa mengenai kapasitor SMD di sekitar socket atau bahkan masuk ke socket pin. Kekurangan: gap udara tersisa, konduktivitas termal buruk. Gunakan: rice grain (NVIDIA saran) atau pea-size (Intel saran)."},
  {"question":"Apa yang terjadi jika PSU dipasang dengan watt terlalu kecil untuk sistem (undersized PSU)?","options":["Sistem tidak bisa booting sama sekali","Sistem bisa boot tapi crash atau restart saat peak load (gaming/render) karena PSU tidak bisa deliver arus yang dibutuhkan","PSU otomatis menyesuaikan output untuk mencukupi kebutuhan","GPU tidak akan terdeteksi oleh sistem"],"answer":1,"difficulty":2,"explanation":"Undersized PSU: komponen tidak mendapat arus cukup saat peak load. GPU RTX 4090 bisa draw 450W burst — PSU 500W untuk sistem dengan CPU 150W dan GPU 450W = disaster. Gejala: random crash, blue screen, shutdown mendadak saat gaming. Kalkulasi PSU: jumlah TDP semua komponen + 20% headroom = minimum PSU watt. Efisiensi 80+ Bronze/Gold juga penting."},
  {"question":"Sistem hanya menampilkan layar hitam setelah semua komponen dipasang. Langkah troubleshooting pertama yang paling logis adalah...","options":["Langsung format dan install ulang OS","Periksa koneksi kabel display (HDMI/DP ke GPU atau motherboard), pastikan RAM terpasang di slot yang benar, dan cek apakah GPU membutuhkan power konektor tambahan","Ganti PSU dengan yang baru","Kirim ke service center"],"answer":1,"difficulty":1,"explanation":"Black screen checklist: (1) Pastikan monitor tersambung ke GPU (bukan onboard jika ada GPU dedicated); (2) RAM di slot yang benar (slot 2&4 biasanya untuk dual-channel); (3) GPU membutuhkan 8-pin atau 16-pin power dari PSU; (4) Dengarkan POST beep code dari speaker; (5) Coba satu stick RAM. Troubleshoot secara sistematis sebelum mengganti komponen."},
  {"question":"BIOS/UEFI POST beep code tiga kali pendek pada kebanyakan sistem menandakan masalah pada...","options":["Harddisk tidak terdeteksi","RAM — bisa berupa kerusakan modul, salah slot, atau ketidakcocokan XMP profile","CPU tidak kompatibel dengan motherboard","GPU tidak terdeteksi"],"answer":1,"difficulty":2,"explanation":"POST beep codes bervariasi per BIOS vendor. Umum: 1 beep pendek = OK. 3 beep pendek (AMI BIOS) = RAM error. Troubleshoot RAM: (1) Reseat modul, (2) Coba satu modul di slot A2, (3) Coba modul di PC lain, (4) Clear CMOS untuk reset XMP. Catatan: beep code tidak universal — selalu refer ke manual motherboard spesifik."},
  {"question":"Fungsi konektor EPS 8-pin (4+4 pin CPU) yang terpisah dari konektor ATX 24-pin adalah...","options":["Menyuplai daya ke RAM","Menyuplai daya khusus ke CPU (VRM — Voltage Regulator Module), terpisah dari daya komponen lain","Menghubungkan PSU ke casing","Backup power jika PSU utama gagal"],"answer":1,"difficulty":1,"explanation":"ATX 24-pin: power untuk motherboard secara umum (PCIe slots, USB controllers, chipset, dll). EPS 8-pin (CPU power): dedicated power line untuk VRM (Voltage Regulator Module) yang menghasilkan voltase CPU. Sistem tidak akan boot tanpa EPS connector. High-end motherboard punya 2x EPS 8-pin untuk overclocking — VRM butuh lebih banyak arus."},
  {"question":"Alasan M.2 NVMe SSD jauh lebih cepat dari SATA SSD adalah...","options":["M.2 menggunakan chip flash yang berbeda","NVMe menggunakan PCIe interface langsung (4-8 lane) dengan protokol yang dioptimalkan untuk flash, menghilangkan overhead SATA AHCI yang dirancang untuk HDD","M.2 form factor secara fisik lebih dekat ke CPU","NVMe tidak memerlukan driver khusus"],"answer":1,"difficulty":2,"explanation":"SATA SSD: max ~550 MB/s (SATA III limit), menggunakan AHCI protokol yang punya queue depth rendah dan dirancang untuk HDD dengan latency tinggi. NVMe PCIe 3.0 x4: ~3500 MB/s sequential. PCIe 4.0 x4: ~7000 MB/s. PCIe 5.0 x4: ~14000 MB/s. NVMe juga punya queue depth jauh lebih dalam (65535 queue, 65535 commands per queue vs AHCI 1 queue, 32 commands)."},
  {"question":"Dalam proses merakit PC, grounding diri (menggunakan anti-static wrist strap atau menyentuh casing metal) penting karena...","options":["Untuk menghangatkan tangan agar lebih mudah memegang komponen kecil","Static electricity (ESD) yang terakumulasi di tubuh bisa merusak komponen elektronik sensitif saat disentuh","Agar sidik jari tidak meninggalkan bekas di komponen","Grounding meningkatkan kualitas sinyal elektrik"],"answer":1,"difficulty":1,"explanation":"ESD (Electrostatic Discharge): tubuh manusia bisa menyimpan ribuan volt static. Saat menyentuh komponen (IC, RAM, GPU), discharge ini bisa merusak transistor nanometer yang sangat sensitif — kerusakan bisa langsung atau delayed (komponen berfungsi tapi tidak stabil). Mitigasi: antistatic wrist strap ke casing grounded, kerja di lantai non-karpet, pegang tepi PCB bukan chip."},
  {"question":"PCIe x16 slot fisik bisa beroperasi pada bandwidth x8 atau x4 karena...","options":["Slot selalu beroperasi penuh sesuai ukuran fisik","PCIe lanes dari CPU/chipset terbatas dan dibagi antar slot — slot x16 fisik bisa mendapat hanya x8 lanes jika slot lain digunakan atau platform entry-level","PCIe otomatis throttle untuk menghemat daya","Kecepatan PCIe tergantung GPU yang dipasang"],"answer":1,"difficulty":2,"explanation":"PCIe lane budget CPU: Intel Core i9: 20 lanes PCIe 5.0 (16 ke GPU + 4 ke SSD). Jika dua GPU dipasang: 8+8. Chipset tambah lebih banyak lane tapi melalui DMI (bottleneck). B-series motherboard sering mengunci slot bawah di x4 atau x1. Untuk GPU x4 vs x16: dalam gaming perbedaan minimal (<5%), tapi untuk multi-GPU professional atau 4x NVMe SSD, lane budget kritis."},
  {"question":"Setelah merakit PC dan menyalakannya pertama kali, system masuk BIOS/UEFI dan menampilkan RAM berjalan di kecepatan default (2133/2400MHz) bukan kecepatan rated (3200/4800MHz). Solusinya adalah...","options":["Beli RAM baru yang sesuai","Aktifkan XMP (Intel) atau EXPO (AMD) profile di BIOS settings","Perbarui OS agar RAM terdeteksi dengan benar","Pasang ulang RAM di slot yang berbeda"],"answer":1,"difficulty":1,"explanation":"JEDEC default: DDR4 boot di 2133MHz, DDR5 di 4800MHz terlepas label 'DDR4-3600' atau 'DDR5-7200'. XMP (eXtreme Memory Profile) / EXPO (Extended Profiles for Overclocking): preset yang disimpan di chip SPD RAM. Aktifkan di BIOS → system akan menggunakan timing dan voltase yang sudah ditest oleh produsen RAM untuk kecepatan rated. Aman dan digaransi oleh produsen."},
  {"question":"Ketika memasang GPU di slot PCIe, tanda berhasil terpasang dengan benar adalah...","options":["Suara 'klik' dari retention clip di ujung slot PCIe dan GPU duduk rata sejajar dengan panel belakang casing","GPU terasa panas setelah dipasang","LED indikator GPU menyala merah","GPU langsung terdeteksi di Device Manager sebelum driver diinstall"],"answer":0,"difficulty":1,"explanation":"Retention clip (latch) PCIe: mekanisme penguncian di ujung slot yang 'klik' saat GPU fully seated. Tanpa klik ini, GPU mungkin tidak terhubung penuh (pin tidak kontak sempurna) → GPU tidak terdeteksi atau performa buruk. Pastikan juga: GPU tidak miring, bracket panel belakang terpasang rapi, power konektor terpasang sebelum menghidupkan PC."},
  {"question":"Liquid cooling AIO (All-In-One) vs air cooling tower: kapan AIO lebih direkomendasikan?","options":["AIO selalu lebih baik dari air cooling dalam semua kondisi","AIO direkomendasikan untuk CPU TDP sangat tinggi (>200W), build compact ITX, atau kebutuhan estetika — air cooling tower besar sering lebih baik dalam nilai dan keandalan","AIO lebih murah sehingga selalu dipilih untuk budget build","AIO tidak memerlukan maintenance apapun selamanya"],"answer":1,"difficulty":2,"explanation":"Air cooling tower (misalnya Noctua NH-D15, be quiet! Dark Rock Pro): pendinginan sangat baik untuk CPU mainstream, sangat andal (tidak ada cairan, pump, atau fitting), murah. AIO 240/360mm: perlu untuk CPU 200W+ (Core i9-14900K, Ryzen 9 7950X), form factor ITX (tidak muat tower besar), atau preferensi estetis. Risk AIO: pump failure, kebocoran, perlu ganti setelah 3-5 tahun."},
  {"question":"Urutan benar dalam proses memasang CPU cooler setelah CPU terpasang di socket adalah...","options":["Pasang backplate → oles thermal paste → pasang cooler → kencangkan screw diagonal bergantian","Oles thermal paste → pasang backplate → pasang cooler → kencangkan screw satu per satu sepenuhnya","Kencangkan semua screw kuat-kuat dulu lalu oles thermal paste","Pasang cooler tanpa thermal paste terlebih dahulu untuk test"],"answer":0,"difficulty":2,"explanation":"Prosedur: (1) Pasang backplate di belakang motherboard jika diperlukan; (2) Oles thermal paste di tengah CPU (pea-size atau thin layer); (3) Posisikan cooler di atas CPU, sejajarkan lubang screw; (4) Kencangkan diagonal (X pattern) secara bergantian dan bertahap — ini memastikan tekanan merata dan mencegah cooler miring yang menyebabkan gap thermal paste tidak rata."},
  {"question":"Keuntungan utama NVMe M.2 2280 form factor dibanding 2.5\" SATA SSD selain kecepatan adalah...","options":["M.2 lebih murah per GB","M.2 langsung tertancap di motherboard tanpa kabel — menghemat ruang dan menyederhanakan cable management","M.2 tidak menghasilkan panas","M.2 lebih tahan terhadap getaran"],"answer":1,"difficulty":1,"explanation":"M.2 2280 (22mm wide, 80mm long): langsung ke slot M.2 motherboard, no SATA data cable, no SATA power cable. SFF (Small Form Factor) builds sangat diuntungkan — ITX build bisa punya penyimpanan cepat tanpa kabel apapun. Kekurangan: M.2 NVMe menghasilkan panas signifikan (controller bisa 80°C+) — banyak motherboard premium kini menyertakan M.2 heatsink."},
  {"question":"Apa perbedaan antara ATX, Micro-ATX, dan Mini-ITX dalam konteks pemilihan casing dan motherboard?","options":["Perbedaan hanya pada warna dan estetika","ATX terbesar (slot/port lebih banyak), Micro-ATX medium (slot lebih sedikit, lebih compact), Mini-ITX terkecil (slot sangat terbatas, ideal build compact)","Mini-ITX lebih bertenaga dari ATX","Micro-ATX tidak kompatibel dengan AMD platform"],"answer":1,"difficulty":1,"explanation":"Form factor hierarchy: E-ATX (305×330mm) → ATX (305×244mm, 7 PCIe slot) → Micro-ATX (244×244mm, 4 PCIe slot) → Mini-ITX (170×170mm, 1 PCIe slot, 2 RAM slot). Casing harus mendukung form factor motherboard. Tradeoff ITX: compact, estetis, tapi: RAM terbatas 2 slot, hanya 1 GPU, thermal lebih challenging, komponen lebih mahal."},
  {"question":"Troubleshooting: PC menyala (fan berputar, LED menyala) tapi tidak ada sinyal ke monitor dan tidak ada beep. Penyebab paling umum adalah...","options":["OS corrupt dan perlu reinstall","RAM tidak terpasang sama sekali atau tidak terdeteksi, CPU tidak terpasang dengan benar, atau GPU bermasalah","Monitor rusak","Power supply terlalu besar untuk sistem"],"answer":1,"difficulty":2,"explanation":"No POST, no beep, no display: (1) RAM — tidak ada/salah slot → tidak ada beep karena speaker belum init; (2) CPU tidak terpasang atau EPS power tidak terpasang; (3) GPU — coba onboard dulu (lepas GPU dedicated); (4) PSU — test dengan PSU lain; (5) Shorting — motherboard menyentuh standoff yang salah posisi. Breadboard test (rakit di luar casing) membantu isolasi masalah."},
  {"question":"Mengapa penting untuk memasang standoff (baut spacer) di posisi yang benar sebelum memasang motherboard ke casing?","options":["Agar motherboard tidak bergerak saat digunakan","Standoff mencegah motherboard menyentuh metal casing yang menyebabkan short circuit, sekaligus memberikan ground point yang benar","Agar pendinginan lebih baik karena ada jarak","Standoff memungkinkan aliran udara di bawah motherboard"],"answer":1,"difficulty":1,"explanation":"Standoff: hex spacer yang dipasang di casing. Fungsi: (1) Elevasi — PCB motherboard tidak menyentuh metal casing (short circuit prevention); (2) Ground — beberapa standoff menjadi titik ground; (3) Stabilitas mekanis. Standoff yang salah posisi (ada standoff di lokasi tidak ada lubang di motherboard) bisa menyebabkan short circuit tersembunyi yang merusak motherboard atau komponen lain."},
  {"question":"Ketika membangun sistem untuk video editing 4K dengan budget terbatas, prioritas komponen yang benar adalah...","options":["GPU terbaik yang bisa dibeli, RAM dan storage tidak penting","RAM besar (32-64GB) dan SSD NVMe cepat untuk storage project karena editing sangat memory dan I/O intensive, CPU multi-core untuk export","Monitor 4K HDR karena itulah yang paling terlihat oleh klien","PSU mahal dengan efisiensi 90%+ untuk menghemat listrik"],"answer":1,"difficulty":2,"explanation":"Video editing bottlenecks: (1) RAM: timeline besar, preview buffer, effect rendering butuh 32-64GB; (2) Storage I/O: 4K raw footage bisa 500MB/s+ read — NVMe SSD untuk project, HDD untuk archive; (3) CPU: multi-core untuk export (Premiere, DaVinci Resolve sangat multi-threaded); (4) GPU: CUDA/OpenCL acceleration untuk effects tapi bukan prioritas tertinggi vs RAM+storage untuk most editors."},
  {"question":"Fungsi debug LED atau Q-code display pada high-end motherboard adalah...","options":["Menampilkan suhu CPU secara real-time","Menampilkan kode POST error untuk membantu troubleshooting — menunjukkan tepat di tahap mana system gagal boot","Indikator estetika yang bisa dikustomisasi warnanya","Menampilkan kecepatan RAM saat ini"],"answer":1,"difficulty":2,"explanation":"Q-code/POST code display (7-segment atau LED panel): selama POST, kode berubah sesuai tahap inisialisasi (CPU init → memory training → PCIe init → boot device detection). Jika hang di kode tertentu, bisa langsung identify masalah: kode 'A0' = OS boot, 'd6' = no console output device, '00' = CPU issue. Jauh lebih informatif dari beep code — krusial untuk troubleshooting build baru."},
  {"question":"Ketika memasang multiple case fan untuk airflow optimal, konfigurasi yang paling direkomendasikan adalah...","options":["Semua fan intake (masuk) untuk tekanan positif maksimal","Intake di depan/bawah dan exhaust di belakang/atas untuk menciptakan aliran udara yang konsisten dari depan ke belakang","Semua fan exhaust untuk membuang panas secepat mungkin","Tidak perlu case fan selama ada CPU cooler yang baik"],"answer":1,"difficulty":2,"explanation":"Airflow konvensi: udara panas naik (konveksi). Optimal: intake front/bottom (udara segar masuk) → melewati GPU, CPU → exhaust rear/top (panas keluar). Positive pressure (intake > exhaust): sedikit lebih banyak intake fan — debu masuk tapi bisa difilter. Negative pressure (exhaust > intake): debu masuk dari celah tak terfilter. Seimbang atau sedikit positive pressure dengan filter adalah best practice."},
  {"question":"Thermal throttling pada CPU terjadi ketika...","options":["CPU di-overclock terlalu tinggi oleh pengguna","Suhu CPU melebihi batas aman (Tjmax), CPU secara otomatis mengurangi clock speed dan/atau voltage untuk menurunkan suhu","CPU terlalu dingin akibat water cooling ekstrem","RAM tidak kompatibel dengan CPU menyebabkan overheating"],"answer":1,"difficulty":2,"explanation":"Thermal throttling: mekanisme proteksi built-in. Intel: Tjmax biasanya 100°C. AMD: 95°C (Ryzen 7000). Saat suhu mencapai limit, CPU menurunkan multiplier (clock speed turun) → performance drop terlihat. Gejala: CPU usage 100% tapi performa rendah, clock speed tidak mencapai boost clock. Solusi: ganti thermal paste, upgrade cooler, perbaiki airflow casing."},
  {"question":"Mengapa SATA port menggunakan hot-swappable design sedangkan PCIe slot tidak?","options":["PCIe lebih mahal sehingga tidak dirancang untuk sering diganti","SATA dirancang untuk storage yang mungkin perlu diganti tanpa matikan sistem, PCIe adalah bus berkeecepatan tinggi dengan komponen yang butuh re-initialize saat terpasang","SATA menggunakan protokol yang lebih sederhana","PCIe tidak mendukung hot-swap karena alasan lisensi"],"answer":1,"difficulty":3,"explanation":"SATA hot-swap: eSATA dan server backplane mendukung plug/unplug storage saat sistem hidup — AHCI dan driver storage mendukung detection/removal event. PCIe: bus beroperasi dengan enumeration saat boot (PCI bus scan) — menambah/mencabut device saat sistem running memerlukan driver dan OS support khusus (Thunderbolt mengimplementasikan ini dengan tunneling PCIe via hot-plug capable interface)."}
],
12: [
  {"question":"Kapan sebaiknya thermal paste diganti pada CPU yang telah digunakan selama beberapa tahun?","options":["Setiap 6 bulan secara rutin","Ketika suhu CPU mulai tinggi secara abnormal atau sekitar setiap 3-5 tahun (tergantung kualitas paste)","Thermal paste tidak pernah perlu diganti","Hanya ganti jika CPU atau cooler diganti"],"answer":1,"difficulty":2,"explanation":"Thermal paste berkualitas baik (Noctua NT-H1, Thermal Grizzly Kryonaut) bertahan 3-5 tahun sebelum degradasi signifikan. Tanda harus diganti: suhu CPU meningkat 10-15°C dari biasanya, throttling yang belum ada sebelumnya. Proses: bersihkan paste lama dengan isopropyl alcohol ≥90%, aplikasikan pasta baru tipis-merata, pasang cooler kembali."},
  {"question":"Cara paling aman membersihkan debu dari heatsink CPU dan GPU tanpa merusak komponen adalah...","options":["Gunakan vacuum cleaner langsung ke heatsink dengan daya penuh","Gunakan compressed air can atau air blower dari jarak aman (15-20cm), tahan fan dengan jari agar tidak overspin saat diblow","Cuci komponen dengan air bersih lalu keringkan","Gunakan kain basah untuk membersihkan fins heatsink"],"answer":1,"difficulty":1,"explanation":"Compressed air: efektif untuk tiup debu dari fins. PENTING: tahan fan blade dengan jari/stick kecil — fan yang diputar oleh udara bertekanan tanpa beban bisa berputar sangat cepat, merusak bearing atau menghasilkan back-EMF yang merusak controller. Jangan gunakan vacuum (static electricity). Isopropyl alcohol untuk membersihkan thermal paste dan kontak elektrik."},
  {"question":"Blue Screen of Death (BSOD) dengan kode 'MEMORY_MANAGEMENT' paling sering disebabkan oleh...","options":["Harddisk hampir penuh","RAM rusak, longgar, atau tidak kompatibel; bisa juga driver atau malware","Processor terlalu panas","GPU driver corrupt"],"answer":1,"difficulty":2,"explanation":"MEMORY_MANAGEMENT BSOD: (1) RAM fisik rusak → test dengan MemTest86 (minimal 2 pass); (2) RAM longgar → reseat modul; (3) XMP/EXPO tidak stabil → set ke JEDEC default di BIOS; (4) Malware memanipulasi memori; (5) Driver buggy yang akses memori tidak valid. MemTest86 bisa run dari USB sebelum OS boot — cek overnight untuk komprehensif."},
  {"question":"HDD (Hard Disk Drive) menunjukkan tanda akan segera gagal jika S.M.A.R.T menampilkan...","options":["Suhu operasional di atas 40°C","Reallocated Sector Count tinggi, Current Pending Sector tinggi, atau Uncorrectable Sector Count > 0","Spin-up time lebih dari 5 detik","Power-on hours di atas 10.000 jam"],"answer":1,"difficulty":2,"explanation":"Critical S.M.A.R.T attributes: (1) Reallocated Sector Count (ID 5): bad sector yang sudah di-reallocate ke spare area → nilai meningkat = HDD mulai rusak fisik; (2) Current Pending Sector (ID 197): sector yang suspect, menunggu test; (3) Uncorrectable Sector (ID 198): sector yang tidak bisa dibaca atau ditulis → data loss imminent. Tool: CrystalDiskInfo (Windows), smartctl (Linux). Backup SEGERA jika angka ini > 0."},
  {"question":"PC yang tiba-tiba mati sendiri (bukan restart) saat sedang load penuh paling sering disebabkan oleh...","options":["Virus yang memprogram shutdown otomatis","PSU tidak cukup kuat atau mulai rusak, overheating CPU/GPU menyebabkan thermal shutdown, atau koneksi power longgar","RAM penuh menyebabkan sistem crash","Harddisk penuh menyebabkan sistem mati"],"answer":1,"difficulty":2,"explanation":"Sudden shutdown (bukan restart): (1) PSU gagal deliver arus saat peak load → OCP (Over Current Protection) trip; (2) CPU atau GPU mencapai Tjmax dan emergency shutdown (berbeda dari throttling); (3) Koneksi kabel power longgar; (4) Motherboard protection circuit. Test: stress test dengan HWMonitor terbuka — pantau suhu dan voltase. PSU tester untuk voltase PSU."},
  {"question":"Cara yang benar untuk membersihkan kontak emas pada RAM sebelum dipasang ulang adalah...","options":["Gosok dengan penghapus pensil (eraser) untuk membersihkan oksidasi ringan, lalu tiup debu","Cuci dengan air sabun dan keringkan sepenuhnya","Gunakan amplas halus untuk menghaluskan permukaan","Tidak perlu dibersihkan — kontak emas tidak teroksidasi"],"answer":0,"difficulty":1,"explanation":"Penghapus pensil (eraser): abrasif sangat halus yang efektif membersihkan oksidasi tipis atau kontaminan pada kontak emas. Gosok perlahan satu arah, tiup sisa karet. Isopropyl alcohol ≥90% juga bisa digunakan untuk kontak yang lebih terkontaminasi. Jangan gunakan: air, bahan kimia keras, atau abrasif kasar yang bisa mengikis lapisan emas."},
  {"question":"Ketika menginstall ulang OS Windows, mengapa penting untuk install driver chipset dan driver storage sebelum driver lainnya?","options":["Karena Windows Update memerlukan driver ini untuk berjalan","Driver chipset mengaktifkan komunikasi penuh antara CPU, RAM, dan perangkat lainnya; driver storage memungkinkan OS mengakses SSD/HDD dengan protokol yang benar (NVMe)","Driver ini harus diinstall dalam urutan tertentu karena lisensi Windows","Untuk mengaktifkan Windows Defender"],"answer":1,"difficulty":2,"explanation":"Driver installation order: (1) Chipset driver (Intel INF/AMD Chipset) → aktivasi PCIe lanes, USB controller, SATA controller dengan benar; (2) Storage driver (Intel RST/NVMe driver) untuk SSD optimal; (3) GPU driver; (4) Audio, NIC, dll. Tanpa chipset driver yang benar, komponen mungkin berjalan dalam compatibility mode yang lebih lambat. Device Manager akan menampilkan '!' pada perangkat tanpa driver proper."},
  {"question":"Suara 'klik' berulang dari harddisk (click of death) menandakan...","options":["HDD memerlukan defragmentasi segera","Read/write head mengalami masalah mekanis serius — backup data segera dan siapkan penggantian HDD","HDD sedang mengakses data dalam jumlah besar (normal)","SATA cable perlu diganti"],"answer":1,"difficulty":1,"explanation":"Click of death: actuator arm mencoba memposisikan head tapi gagal, mundur ke parking position, mencoba lagi — menghasilkan suara klik berulang. Penyebab: head crash (head menyentuh platter), failed spindle motor, corrupt firmware, power issue. Data recovery kemungkinan masih bisa dilakukan oleh professional recovery service jika tidak di-power-on terlalu lama setelahnya. BACKUP SEGERA."},
  {"question":"Cara aman melakukan update BIOS/UEFI pada motherboard adalah...","options":["Update BIOS saat sistem sedang render video berat untuk test stabilitas","Gunakan power yang stabil (sambungkan ke UPS atau jangan lewat baterai laptop yang hampir habis), download file dari situs resmi, jangan matikan sistem saat update berlangsung","Selalu update BIOS ke versi terbaru setiap minggu","Update BIOS bisa dilakukan melalui OS tanpa mempersiapkan apapun"],"answer":1,"difficulty":2,"explanation":"BIOS flash risk: power failure saat update = motherboard brick (tidak bisa boot). Mitigasi: (1) Sambungkan ke UPS atau pastikan baterai penuh (laptop); (2) Download dari situs resmi produsen — file corrupt menyebabkan brick; (3) Jangan matikan/restart selama proses (biasanya 2-10 menit); (4) Baca release notes — update hanya jika ada fix yang relevan. 'If it ain't broke, don't fix it' berlaku untuk BIOS."},
  {"question":"Apa yang harus dilakukan pertama kali sebelum membuka casing dan menyentuh komponen internal PC?","options":["Cuci tangan dengan sabun untuk menghilangkan minyak","Matikan PC dan cabut kabel power dari stopkontak (bukan hanya menekan tombol power softkey), lalu discharge statis dengan menyentuh casing metal","Nyalakan PC terlebih dahulu untuk melihat komponen mana yang bermasalah","Lepas semua USB device dan peripheral"],"answer":1,"difficulty":1,"explanation":"Safety procedure: (1) Soft power off = PSU masih standby (5V always-on) — bisa menyengat atau short; (2) Cabut dari stopkontak = benar-benar mati; (3) Tekan tombol power beberapa kali setelah cabut untuk discharge kapasitor; (4) Touch metal chassis untuk discharge ESD. Penting: bahkan kapasitor besar dalam PSU bisa menyimpan charge berbahaya — jangan buka PSU tanpa training khusus."},
  {"question":"Disk defragmentation penting untuk HDD tapi tidak diperlukan (bahkan merugikan) untuk SSD karena...","options":["SSD tidak menyimpan data secara tersebar","HDD akses data tersebar memerlukan perpindahan fisik head (waktu seek), SSD akses semua lokasi dalam waktu sama (random access). Defrag SSD menyebabkan write cycle sia-sia yang mengurangi umur SSD","SSD tidak memiliki filesystem yang memerlukan defrag","Defrag tidak bisa dilakukan pada SSD secara teknis"],"answer":1,"difficulty":2,"explanation":"HDD: data tersebar di track berbeda → head harus bergerak fisik → seektime tinggi. Defrag mengkonsolidasi fragmen untuk akses sequential — signifikan meningkatkan performa. SSD: tidak ada moving parts, random access = sequential access latency. Defrag SSD hanya menambah write cycle tanpa manfaat (SSD punya write endurance terbatas). Windows otomatis menjalankan TRIM pada SSD (bukan defrag)."},
  {"question":"Kapasitor kembung (bulging capacitor) pada motherboard menandakan...","options":["Kapasitor sudah dicharge penuh dan normal","Kapasitor telah gagal — top cap membengkok akibat tekanan internal dari elektrolit yang terdegradasi, menyebabkan ketidakstabilan sistem","Kapasitor memerlukan penggantian baterai internal","Kapasitor terlalu kecil untuk rating voltase sistem"],"answer":1,"difficulty":2,"explanation":"Electrolytic capacitor aging: elektrolit mengering atau reaksi kimia menghasilkan gas → top membengkung. Gejala: sistem crash acak, tidak mau boot, voltase tidak stabil. Identifikasi: top kapasitor seharusnya rata, bukan cembung. Pada motherboard vintage (2000-2008 banyak kasus 'capacitor plague' — kapasitor Taiwan low-quality). Solusi: recapping oleh teknisi yang bisa soldering SMD komponen."},
  {"question":"Tools wajib untuk teknisi PC dalam melakukan troubleshooting hardware adalah...","options":["Hanya multimeter dan obeng","Multimeter (voltase, kontinuitas), POST test card, USB bootable MemTest86/HDD diagnostic, thermal camera atau sensor suhu, dan replacement komponen yang diketahui baik untuk swap test","Hanya software Windows Event Viewer","Oscilloscope untuk semua troubleshooting"],"answer":1,"difficulty":2,"explanation":"Toolkit lengkap: (1) Multimeter: cek voltase PSU, koneksi; (2) POST card: tampilkan kode error di sistem yang tidak boot ke OS; (3) USB bootable tool: MemTest86 (RAM), Victoria/HDTune (HDD), Prime95/FurMark (stress test); (4) Thermal monitoring: HWMonitor, GPU-Z; (5) Swap test: known-good komponen untuk isolasi masalah. Metodologi: isolasi variabel satu per satu."},
  {"question":"Ketika PC menunjukkan gejala 'No Signal' sesaat setelah boot (saat Windows loading screen) dan memerlukan restart, kemungkinan penyebabnya adalah...","options":["Monitor rusak permanen","GPU driver crash (TDR — Timeout Detection and Recovery), GPU overheating, GPU mulai rusak, atau koneksi display cable longgar","PSU tidak cukup kuat","RAM tidak kompatibel dengan Windows"],"answer":1,"difficulty":2,"explanation":"Display loss saat loading/gaming: (1) GPU TDR: driver reset karena GPU tidak respond dalam waktu ditentukan — cek Event Viewer, update/rollback driver; (2) GPU thermal throttling ekstrem atau shutdown; (3) Koneksi HDMI/DP longgar (vibration saat boot); (4) GPU hardware failure (VRM, VRAM dying) → artifact sebelum crash. Benchmark GPU (FurMark) untuk reproduce dan monitor suhu."},
  {"question":"Mengapa Windows Event Viewer berguna dalam troubleshooting masalah PC yang intermittent (tidak konsisten)?","options":["Event Viewer menampilkan suhu CPU secara real-time","Event Viewer menyimpan log sistem secara kronologis termasuk error, warning, dan crash info (termasuk BSOD minidump reference) yang membantu identify pola masalah","Event Viewer hanya berguna untuk network admin","Event Viewer bisa memperbaiki error secara otomatis"],"answer":1,"difficulty":2,"explanation":"Event Viewer (eventvwr.msc): Windows Logs → System dan Application. Cari: Critical events, Error 41 (Kernel-Power = unexpected shutdown), Error 6008 (unexpected shutdown log), BSOD source (System log sekitar waktu crash). Application Log: crash aplikasi spesifik. Event ID bisa di-Google untuk solusi. Untuk BSOD: analyze minidump di C:\\Windows\\Minidump dengan WinDbg atau WhoCrashed."},
  {"question":"Apa penyebab umum PC restart sendiri (bukan shutdown) saat gaming atau render berat?","options":["Game atau software memiliki bug yang merestart PC","Overheating CPU/GPU menyebabkan emergency restart, PSU overcurrent protection trip, atau Windows BSOD dikonfigurasi auto-restart (default)","RAM terlalu penuh menyebabkan restart","Harddisk hampir penuh menyebabkan sistem restart"],"answer":1,"difficulty":2,"explanation":"Auto-restart vs shutdown: (1) Overheating: CPU/GPU mencapai Tjmax → immediate shutdown (bukan restart). Restart biasanya = BSOD; (2) PSU OCP (Over Current Protection): restart/shutdown mendadak; (3) BSOD auto-restart: Windows default restart pada BSOD — disable untuk lihat error code (Control Panel → System → Advanced → Startup and Recovery → uncheck 'Automatically restart'); (4) Check HWMonitor selama stress test."},
  {"question":"Fungsi CMOS battery (baterai CR2032) pada motherboard adalah...","options":["Menyuplai daya darurat saat listrik mati untuk menyelamatkan data","Menyimpan pengaturan BIOS/UEFI dan jam real-time (RTC) saat PC mati — tanpa baterai, setting BIOS reset ke default setiap kali PC dimatikan","Charging baterai internal PC untuk UPS fungsi","Menyediakan power untuk USB charging saat PC mati"],"answer":1,"difficulty":1,"explanation":"CMOS battery: lithium coin cell CR2032 (~3V), umur 5-10 tahun. Fungsi: (1) Retain BIOS settings (XMP profile, boot order, custom settings); (2) Power RTC (Real-Time Clock) agar jam sistem akurat saat boot. Tanda baterai habis: jam sistem selalu reset ke 2000/2002, BIOS settings hilang setiap boot, kadang sistem tidak mau boot. Ganti dengan CR2032 baru — murah dan mudah."},
  {"question":"Teknik 're-balling' pada GPU yang mengalami solder joint failure (seperti GeForce 8800 GT era atau solder NVIDIA 90nm) adalah...","options":["Proses mengecat ulang body GPU","Proses mengganti solder ball (BGA) di bawah chip GPU menggunakan rework station — memerlukan hot air station, reballing stencil, dan leaded solder","Overclocking GPU untuk stabilisasi","Proses membersihkan PCB GPU dengan ultrasonic cleaner"],"answer":1,"difficulty":3,"explanation":"BGA (Ball Grid Array) failure: solder ball retak akibat thermal cycling bertahun-tahun (expand/contract). Gejala: display artifact, crash, tidak terdeteksi. Reballing: (1) Heat chip dengan hot air station untuk lepaskan dari PCB; (2) Bersihkan solder lama; (3) Aplikasikan flux dan solder balls baru via stencil; (4) Reflow. Alternatif murah yang tidak permanen: 'oven trick' atau heat gun — bisa memperpanjang hidup sementara."},
  {"question":"Network adapter menampilkan 'Limited Connectivity' atau tidak bisa mendapat IP address. Troubleshooting pertama adalah...","options":["Beli network adapter baru","Coba 'ipconfig /release' lalu 'ipconfig /renew', restart DHCP client service, atau reset TCP/IP stack dengan 'netsh int ip reset'","Format ulang Windows","Ganti kabel ethernet"],"answer":1,"difficulty":2,"explanation":"Limited connectivity troubleshoot: (1) ipconfig /release → /renew: minta IP baru dari DHCP server; (2) Restart service: services.msc → DHCP Client → Restart; (3) netsh int ip reset resetlog.txt: reset TCP/IP stack ke default; (4) netsh winsock reset: reset Winsock catalog; (5) Cek apakah router/switch normal (coba device lain); (6) Device Manager — network adapter ada '!'?; (7) Update/rollback driver."},
  {"question":"Ketika SSD mulai penuh mendekati kapasitas, performa SSD menurun karena...","options":["SSD membutuhkan ruang kosong untuk OS swap file","SSD controller memerlukan ruang kosong (over-provisioning + user-free space) untuk garbage collection dan wear leveling — tanpa ruang bebas, write amplification meningkat drastis","SSD membatasi kecepatan sendiri saat hampir penuh untuk mencegah kerusakan","File system menjadi lebih complex saat SSD hampir penuh"],"answer":1,"difficulty":3,"explanation":"SSD write mechanism: NAND tidak bisa tulis langsung ke cell yang sudah berisi data — harus erase dulu (erase granularity lebih besar dari write). Garbage collection: SSD mengkonsolidasi data valid, erase block kosong, siap tulis ulang. Tanpa free space: GC tidak bisa bekerja efisien → write amplification tinggi → performa menurun. Rekomendasi: jangan isi SSD lebih dari 75-80% kapasitas."},
  {"question":"Mengapa tidak disarankan menggunakan software 'cleaner' atau 'optimizer' pihak ketiga seperti CCleaner untuk membersihkan registry Windows?","options":["Software tersebut berbayar dan terlalu mahal","Registry cleaning bisa menghapus entry yang terlihat 'orphan' tapi masih dibutuhkan oleh aplikasi, menyebabkan crash; risiko kerusakan lebih besar dari manfaat performa yang minimal","Hanya Microsoft yang boleh memodifikasi registry","Software cleaner menyebabkan virus"],"answer":1,"difficulty":2,"explanation":"Registry cleaning controversy: Modern Windows (10/11) mengelola registry sendiri dengan sangat baik. Software cleaner sering menghapus keys berdasarkan heuristic yang tidak sempurna — beberapa 'orphan' keys masih dibutuhkan. Manfaat performa nyata: nihil (registry load bukan bottleneck performa). Risiko: aplikasi crash setelah cleaning. Microsoft sendiri merekomendasikan tidak menggunakan registry cleaner pihak ketiga (KB2563254)."},
  {"question":"Proses POST (Power-On Self-Test) yang dijalankan BIOS/UEFI saat PC menyala melakukan hal berikut dalam urutan...","options":["Load OS → Test hardware → Tampilkan BIOS screen","Inisialisasi CPU → Test memori → Deteksi storage dan perangkat → Tampilkan splash screen → Handoff ke bootloader OS","Test jaringan → Inisialisasi GPU → Load driver → Booting OS","Tidak ada urutan tertentu — POST berjalan acak"],"answer":1,"difficulty":2,"explanation":"POST sequence: (1) CPU init dan self-test; (2) Chipset init; (3) RAM detection dan memory test (MemTest basic); (4) GPU init (VBIOS); (5) Storage detection (SATA, NVMe, USB); (6) Splash screen / UEFI logo; (7) Boot device selection (sesuai boot order); (8) Load bootloader (Windows Boot Manager / GRUB); (9) Handoff ke OS kernel. POST card menampilkan kode di setiap tahap."},
  {"question":"Cara paling efektif mengatasi PC yang overheating karena faktor lingkungan (ruangan panas, ventilasi buruk) adalah...","options":["Underclocking CPU dan GPU secara permanen","Pastikan sirkulasi udara casing baik (bersihkan debu filter, tambah case fan), letakkan PC di area berventilasi, pertimbangkan AC ruangan, dan undervolting CPU/GPU untuk kurangi panas tanpa turunkan performa signifikan","Buka tutup casing agar udara lebih bebas masuk","Ganti semua komponen dengan versi yang lebih hemat daya"],"answer":1,"difficulty":2,"explanation":"Overheating solutions bertahap: (1) Bersihkan debu dari heatsink, filter, fan — debu insulasi termal; (2) Optimal airflow casing; (3) Undervolting: kurangi voltase CPU/GPU sambil pertahankan clock → signifikan kurangi panas (10-20°C) tanpa performa loss; (4) Ganti thermal paste; (5) Upgrade cooler; (6) Lingkungan: AC, elevated PC dari lantai (untuk airflow bawah). Undervolting via Intel XTU, AMD Ryzen Master, MSI Afterburner untuk GPU."},
  {"question":"Perbedaan antara Full Format dan Quick Format saat memformat drive adalah...","options":["Full Format lebih cepat dari Quick Format","Quick Format hanya menghapus file allocation table (FAT/MFT), Full Format juga menulis nol ke seluruh drive untuk verifikasi bad sector","Full Format mengenkripsi data, Quick Format tidak","Tidak ada perbedaan — keduanya menghapus data secara permanen"],"answer":1,"difficulty":1,"explanation":"Quick Format: hapus MFT/FAT, tulis filesystem baru, tandai drive kosong — data masih ada di disk, bisa di-recover dengan software recovery. Cepat (detik-menit). Full Format: Quick Format + tulis nol (atau verifikasi) ke semua sektor — mendeteksi bad sector, membuat recovery lebih sulit. Lambat (jam untuk 1TB HDD). Untuk SSD: gunakan Secure Erase bawaan firmware, bukan full format."}
],
13: [
  {"question":"Resistive RAM (ReRAM/RRAM) menyimpan data dengan cara berbeda dari NAND Flash, yaitu...","options":["Menggunakan muatan elektron seperti Flash tapi dengan kecepatan lebih tinggi","Mengubah resistansi material (memristive material) antara high-resistance (0) dan low-resistance (1) state melalui voltage pulse","Menggunakan medan magnet seperti HDD tapi dalam skala nano","Menggunakan perbedaan suhu antara dua material"],"answer":1,"difficulty":3,"explanation":"ReRAM: material oxide (seperti HfO2) dapat di-switch antara insulating state (high-R = '0') dan conducting state (low-R = '1') menggunakan voltage. Keunggulan vs NAND: faster write, lower power, byte-addressable, lebih baik untuk near-memory computing. Intel Optane menggunakan 3D XPoint (teknologi mirip PCM, bukan ReRAM murni). ReRAM masih dalam komersialisasi — Crossbar Inc., WEEBIT Nano."},
  {"question":"Approximate computing sebagai paradigma baru komputasi mengorbankan keakuratan untuk...","options":["Mengurangi biaya hardware","Meningkatkan efisiensi energi dan kecepatan pada aplikasi yang toleran terhadap error seperti image processing, ML inference, dan sensor data","Memudahkan programming model","Mengurangi kebutuhan memori"],"answer":1,"difficulty":3,"explanation":"Approximate computing: untuk domain aplikasi yang tidak memerlukan bit-exact result (image/video, audio, ML inference, sensor fusion), komputasi approximate menghasilkan output 'good enough' dengan konsumsi daya jauh lebih rendah. Teknik: voltage scaling (lower V → more errors tapi lebih hemat), precision scaling, approximate adder/multiplier. Error dalam output (sedikit noise di gambar) tidak terlihat oleh manusia."},
  {"question":"Die stacking dengan Through-Silicon Via (TSV) berbeda dari koneksi chip 2D konvensional dalam hal...","options":["TSV menggunakan koneksi wireless antar chip","TSV membuat vertical interconnect melalui silicon die, memungkinkan bandwidth sangat tinggi antara chip yang ditumpuk dengan jarak koneksi sangat pendek","TSV hanya digunakan untuk connecting power supply","TSV adalah teknik untuk memperbesar ukuran transistor"],"answer":1,"difficulty":3,"explanation":"TSV: lubang vertikal melalui silicon die, diisi konduktor (tembaga). Chip-chip di-stack vertikal dan dihubungkan via TSV → interconnect panjangnya milimeter, bukan centimeter. Bandwidth: HBM2E menggunakan TSV — 512-bit bus per stack, bandwidth >460 GB/s. Vs wire bonding (2D): TSV jauh lebih pendek, lebih banyak interconnect, latency lebih rendah, power lebih efisien."},
  {"question":"Disaggregated computing dalam data center masa depan memisahkan CPU, memory, dan storage ke resource pool terpisah yang dihubungkan via...","options":["Jaringan WiFi 6E untuk kecepatan tinggi","CXL (Compute Express Link) atau fabric berkecepatan tinggi — memungkinkan server mengakses memory atau accelerator dari pool terpusat sesuai kebutuhan workload","USB 4.0 untuk kompatibilitas luas","InfiniBand untuk semua jenis resource"],"answer":1,"difficulty":3,"explanation":"Disaggregated computing: dalam server tradisional, CPU, DRAM, dan NVMe terikat di satu node — stranded resources (CPU butuh lebih RAM tapi server penuh). Disaggregation via CXL 3.0/fabric: memory pool terpisah, GPU pool terpisah, bisa di-assign dinamis per workload. CXL (Compute Express Link) menggunakan PCIe fisik tapi dengan protokol cache-coherent — CPU bisa mengakses remote memory dengan latency rendah."},
  {"question":"Dataflow architecture (seperti yang dikembangkan untuk AI chip) berbeda dari Von Neumann architecture karena...","options":["Dataflow architecture tidak menggunakan transistor","Eksekusi tidak dikendalikan oleh program counter sequential — instruksi dieksekusi saat semua operand tersedia (data-driven execution)","Dataflow lebih lambat tapi lebih akurat","Dataflow hanya untuk komputasi floating point"],"answer":1,"difficulty":3,"explanation":"Von Neumann: PC sequential, fetch-decode-execute, bottleneck memory. Dataflow: computation graph — setiap node (operation) aktif saat semua input tersedia, menghasilkan output yang mengaktifkan node berikutnya. Massively parallel secara natural, tidak ada shared program counter. Diimplementasikan di TPU (systolic array untuk matmul), Graphcore IPU, Cerebras WSE. Sangat efisien untuk ML inference/training workload."},
  {"question":"Quantum error correction (seperti surface code) diperlukan dalam quantum computing karena...","options":["Quantum computer memiliki bug software yang lebih banyak","Qubit sangat rentan terhadap decoherence dan noise — logical qubit tunggal yang andal memerlukan ratusan hingga ribuan physical qubit yang saling memperbaiki error","Quantum computing memerlukan koreksi untuk efisiensi energi","Error correction membuat quantum computer lebih cepat"],"answer":1,"difficulty":3,"explanation":"Decoherence: qubit kehilangan quantum state akibat interaksi dengan lingkungan (termal, elektromagnetik). Physical qubit error rate: 0.1-1% per gate operation. Surface code: 2D grid qubit fisik, pengukuran syndrome (ancilla qubit) mendeteksi error tanpa collapse data qubit. Threshold theorem: jika error rate fisik < threshold (~1%), error correction bisa bekerja. Saat ini, ~1000 physical qubit per logical qubit untuk 50 tahun operasional."},
  {"question":"CXL (Compute Express Link) tipe 3 memungkinkan...","options":["Menghubungkan GPU dengan kecepatan 3x lebih tinggi","Memory sharing antar multiple host/CPU dengan coherency — memungkinkan server berbagi memory pool secara cache-coherent","Koneksi storage NVMe dengan latensi lebih rendah","Menggantikan PCIe sepenuhnya dengan protokol baru"],"answer":1,"difficulty":3,"explanation":"CXL 1.1/2.0: CPU ↔ accelerator, CPU ↔ memory expander. CXL 3.0 (P-2-P): device-to-device communication, memory sharing coherent antar multiple hosts. Use case: 8 server node berbagi pool 1TB HBM — workload yang butuh lebih RAM dari satu node bisa 'borrow' dari pool. CXL menggunakan PCIe 5.0 fisik (68.6 GT/s per lane) dengan protokol coherency di atasnya."},
  {"question":"Optical interconnect (silicon photonics) dalam processor chip bertujuan menggantikan copper interconnect karena...","options":["Cahaya lebih mudah diproduksi dari listrik","Optical interconnect menawarkan bandwidth lebih tinggi, latensi lebih rendah, dan konsumsi daya lebih rendah per bit untuk jarak yang lebih panjang dibanding copper","Optical tidak memerlukan encoding data","Cahaya tidak menghasilkan panas"],"answer":1,"difficulty":3,"explanation":"Copper interconnect problems: resistance meningkat seiring panjang, bandwidth terbatas oleh skin effect dan crosstalk, power dissipation tinggi. Silicon photonics: modulator mengkonversi sinyal listrik → cahaya, waveguide menggantikan copper trace, photodetector di penerima. Bandwidth: satu wavelength bisa 400Gbps+, WDM (multiple wavelengths) bisa Tbps per fiber. Sudah digunakan di data center interconnect (400G/800G transceivers)."},
  {"question":"Carbon Nanotube Transistor (CNFET) menjanjikan melampaui silicon CMOS karena...","options":["Carbon nanotube lebih murah dari silicon","CNT memiliki carrier mobility jauh lebih tinggi dari silicon dan dapat membentuk transistor yang lebih tipis — potensial untuk scaling di bawah 5nm tanpa masalah leakage silicon","Carbon nanotube dapat diprogram ulang setelah fabrikasi","CNT menggunakan medan magnet alih-alih listrik"],"answer":1,"difficulty":3,"explanation":"Silicon scaling challenges: sub-5nm, quantum tunneling menjadi masalah, leakage current meningkat, sulit mengontrol doping. CNT: diameter ~1nm, ballistic transport (elektron tidak mengalami scattering), on/off ratio tinggi, bandgap yang bisa di-tune. MIT mendemonstrasikan 16-bit CNT processor (2019). Challenge: alignment dan chirality control CNT dalam wafer-scale fabrikasi masih dalam penelitian."},
  {"question":"Processing-in-Memory (PIM) dan Near-Data Computing bertujuan mengatasi masalah...","options":["Kapasitas memori yang terlalu kecil","Memory wall — bottleneck bandwidth dan latensi antara CPU dan memori yang menyebabkan CPU sering idle menunggu data","Keamanan data dalam memori","Kompatibilitas antara CPU dan memori dari vendor berbeda"],"answer":1,"difficulty":3,"explanation":"Memory wall: data movement antara CPU dan DRAM mengkonsumsi 40-60x lebih banyak energi dan memakan waktu 100-200 cycle. PIM: letakkan komputasi di atau dekat chip memori — Samsung AXDIMM, SK Hynix AiM, UPMEM. Near-data computing: GPU HBM dengan compute di logic layer TSV. Eliminasi data movement untuk operasi yang data-intensive (graph processing, genomics, database scan)."},
  {"question":"RISC-V sebagai open-source ISA memberikan keuntungan yang tidak dimiliki ARM atau x86, yaitu...","options":["RISC-V secara hardware lebih cepat dari ARM","Siapapun bisa implementasikan, modifikasi, dan fabrikasi prosesor RISC-V tanpa lisensi fee — mendorong inovasi dan mengurangi lock-in ke satu vendor","RISC-V didukung langsung oleh Intel","RISC-V memiliki instruksi lebih sedikit sehingga lebih mudah diprogram"],"answer":1,"difficulty":3,"explanation":"RISC-V (2010, UC Berkeley): bebas dan open standard. x86: Intel/AMD saja yang boleh fabrikasi tanpa cross-license. ARM: lisensi mahal (core license, architecture license). RISC-V: siapa saja bisa implementasi — dari microcontroller (ESP32-C3) hingga server CPU (SiFive P670, Alibaba XuanTie). Modular extensions: RV32I (base integer) + M (multiply) + F (float) + V (vector). Adopsi cepat di embedded, RISC-V chips di server mulai 2024-2025."},
  {"question":"Chiplet design (seperti AMD Ryzen menggunakan CCD + IOD) memberikan keunggulan yield dibanding monolithic die karena...","options":["Chiplet menggunakan bahan silicon yang berbeda","Die kecil (chiplet) memiliki yield lebih tinggi dari die besar — defect pada satu chiplet hanya buang chiplet itu, bukan seluruh produk; chiplet bisa dibuat di node berbeda yang optimal untuk fungsinya","Chiplet lebih mudah di-cooling dari monolithic die","Chiplet otomatis menggunakan TSMC terbaik"],"answer":1,"difficulty":3,"explanation":"Yield dalam semikonduktor: probabilitas die berfungsi turun eksponensial seiring ukuran die meningkat (defect density × area). AMD Ryzen: CCD (Core Compute Die) kecil di 5nm/7nm (compute-intensive, butuh node terkecil), IOD (I/O Die) lebih besar di 12nm/6nm (toleran node lebih tua, lebih murah). Defect di CCD → buang CCD saja ($30), bukan seluruh chip ($200+). Chiplet juga memungkinkan heterogeneous integration."},
  {"question":"Neuromorphic chip (seperti Intel Loihi 2 atau IBM TrueNorth) menggunakan event-driven computation yang berbeda dari von Neumann karena...","options":["Neuromorphic chip menggunakan DNA computing","Hanya neuron yang menerima spike (event) yang aktif — sangat energy-efficient untuk sparse activation patterns; komunikasi asynchronous antar neuron via spikes bukan clock-driven","Neuromorphic chip tidak memerlukan software","Neuromorphic lebih powerful dari GPU untuk semua task"],"answer":1,"difficulty":3,"explanation":"Neuromorphic: terinspirasi dari otak. Artificial neuron terintegrasi dan menembak spike saat threshold terlampaui. Event-driven: mayoritas neuron dormant pada waktu tertentu (otak manusia: ~1% neuron aktif simultan). Vs GPU: GPU clock-driven, update semua elemen setiap cycle. Neuromorphic: hanya update neuron yang dapat spike → 100-1000x lebih hemat daya untuk sparse workload. IBM TrueNorth: 4096 core, 1M neuron, 256M synapse, 65mW total."},
  {"question":"FPGA (Field Programmable Gate Array) unggul dibanding GPU untuk workload...","options":["Matrix multiplication berskala besar","Latency-critical, deterministic real-time processing seperti network packet processing, HFT trading, radar signal processing — FPGA memberikan latensi nanosecond dengan jitter minimal","Machine learning training","General purpose computing"],"answer":1,"difficulty":3,"explanation":"FPGA: rekonfigurasi hardware, pipeline custom per application, no OS overhead, deterministic timing (nanosecond-level). GPU: high throughput parallel compute tapi non-deterministic (jitter), latency puluhan microsecond. FPGA use cases: (1) Microsoft Azure SmartNIC (Catapult) untuk Bing search acceleration; (2) Xilinx Alveo untuk HFT (<1μs order execution); (3) Qualcomm: LTE/5G baseband processing. Trade-off: sulit diprogram (VHDL/Verilog atau HLS)."},
  {"question":"3D IC (Three-Dimensional Integrated Circuit) berbeda dari 2.5D interposer design dalam hal...","options":["3D IC menggunakan tiga jenis processor berbeda","3D IC menumpuk die secara vertikal dengan TSV langsung antar die aktif, 2.5D menggunakan interposer pasif sebagai perantara — 3D lebih intim integrasinya tapi lebih sulit dalam thermal management","2.5D lebih mahal dari 3D IC","3D IC hanya untuk memory, 2.5D untuk logic"],"answer":1,"difficulty":3,"explanation":"2.5D (HBM + GPU via silicon interposer): die kiri-kanan di atas interposer, TSV dalam interposer — lebih mudah manufacturing, thermal lebih baik. 3D IC (SRAM on logic, seperti Intel Foveros): die di atas die dengan direct TSV — density sangat tinggi (SRAM cache langsung di atas CPU core), bandwidth maksimal, tapi panas dari die bawah sulit keluar. AMD V-Cache (3D V-Cache): 64MB SRAM di atas CCD via hybrid bonding."},
  {"question":"Analog in-memory computing mengeksploitasi physics dari komponen memori untuk...","options":["Menghemat listrik dengan mengurangi frekuensi refresh","Melakukan operasi matriks-vektor multiplication secara simultan dalam array memori menggunakan Ohm's Law dan Kirchhoff's Law — sangat efisien untuk neural network inference","Mempercepat operasi enkripsi AES","Menggantikan cache dengan operasi analog"],"answer":1,"difficulty":3,"explanation":"Analog IMC: store bobot neural network dalam resistive memory (ReRAM/PCM). Input diberikan sebagai voltage per kolom, current yang mengalir (I = V/R, Kirchhoff: jumlah current per baris = dot product). Satu 'clock' melakukan seluruh layer matrix-vector multiply yang pada digital GPU butuh ribuan clock. Challenge: noise, variability antar device, analog-to-digital conversion overhead. IBM, IMEC, Syntiant mengembangkan ini untuk edge AI."},
  {"question":"Domain-Specific Architecture (DSA) seperti Google TPU mengorbankan generalitas untuk...","options":["Kompatibilitas dengan software yang lebih luas","Efisiensi jauh lebih tinggi untuk domain spesifik (matrix multiplication untuk ML) — menggunakan seluruh area silicon untuk systolic array alih-alih general ALU, cache hierarchy kompleks, dan branch predictor","Kemudahan programming","Kemampuan menjalankan sistem operasi sendiri"],"answer":1,"difficulty":3,"explanation":"DSA trade-off: TPU v1 area: 95% systolic array (256x256 = 65536 MAC units), hanya 5% untuk control. CPU yang sama areanya punya: branch predictor, out-of-order engine, complex cache hierarchy, multiple general ALU. Untuk deep learning: TPU 15-30x lebih cepat dengan 30-80x efisiensi daya dari GPU. Tetapi: TPU tidak bisa menjalankan game atau browser. Amortisasi: hanya ekonomis jika DSA digunakan >70% waktu."},
  {"question":"Persistent Memory (seperti Intel Optane DCPMM) dalam mode 'App Direct' memungkinkan aplikasi untuk...","options":["Meningkatkan kecepatan akses DRAM reguler","Langsung mengakses persistent storage dengan latensi mendekati DRAM (~300ns) menggunakan load/store instruksi CPU, tanpa melalui filesystem overhead","Menggantikan GPU untuk accelerated computing","Menggunakan instruksi khusus untuk enkripsi data"],"answer":1,"difficulty":3,"explanation":"Optane DCPMM App Direct mode: OS memetakan persistent memory ke virtual address space. Aplikasi menggunakan CLWB (Cache Line Write Back) + SFENCE untuk persist data ke media (bypass CPU cache untuk durability). Vs file system: eliminasi overhead syscall, VFS, page cache, filesystem. DB seperti SAP HANA dan Redis Enterprise menggunakan ini untuk in-memory database dengan durability tanpa checkpoint overhead."},
  {"question":"Compute-in-Cache architecture menempatkan logic computation di dalam SRAM cache array untuk...","options":["Membuat cache lebih cepat dengan mengurangi ukurannya","Melakukan operasi bitwise atau simple arithmetic langsung di dalam SRAM tanpa membawa data ke CPU core — mengurangi data movement yang dominasi energy consumption","Menggantikan branch predictor","Membuat cache immune terhadap cosmic ray bit flip"],"answer":1,"difficulty":3,"explanation":"SRAM compute-in-cache: modifikasi kecil pada SRAM bitcell memungkinkan AND, OR, XOR, NOR operasi dalam memory array sendiri. Penelitian dari UCSB, MIT, dan Intel Labs: untuk workload seperti bitwise neural network, genomics sequence matching, dan database bitmap operations, eliminasi data movement memberikan 10-100x efisiensi energi. Data tidak perlu perjalanan CPU←→cache: computation terjadi 'in-situ'."},
  {"question":"Teknologi Quantum Dot Cellular Automata (QCA) yang sedang diteliti bertujuan untuk komputasi di bawah limit CMOS dengan cara...","options":["Menggunakan elektron tunggal untuk merepresentasikan bit","Menggunakan konfigurasi muatan dalam sel quantum dot (4 dot, 2 elektron) sebagai bit — propagasi informasi melalui elektrostatis tanpa arus listrik mengalir","Menggunakan foton sebagai pengganti elektron","Menggunakan spin elektron seperti spintronics"],"answer":1,"difficulty":3,"explanation":"QCA: setiap sel terdiri dari 4 quantum dot dan 2 elektron. Elektrostatik paksa elektron ke konfigurasi diagonal (01/10 = '0' atau '1'). Propagasi: sel tetangga saling 'mempengaruhi' posisi elektron tanpa transfer muatan → tidak ada arus mengalir → zero static power dissipation. Potentially operate di 100GHz+ pada suhu sangat rendah. Challenge: operating temperature (saat ini: ~1K), nanofabrikasi precision."},
  {"question":"Hardware Security Module (HSM) dan Trusted Platform Module (TPM) berbeda dalam scope penggunaannya:","options":["HSM dan TPM identik secara fungsional","HSM: dedicated hardware crypto accelerator untuk enterprise (root of trust untuk CA, key management server), TPM: chip kecil di motherboard consumer/enterprise untuk platform attestation, secure boot, disk encryption key storage","TPM lebih powerful dari HSM untuk semua task","HSM digunakan di smartphone, TPM di server"],"answer":1,"difficulty":3,"explanation":"TPM (TCG standard): chip onboard motherboard, fungsi: (1) Secure key storage (BitLocker key), (2) Platform attestation (mengukur boot chain integritas), (3) Random number generation. HSM (Hardware Security Module): dedicated appliance/card dengan FIPS 140-2 Level 3/4 certification, physical tamper-resistant (self-destruct bila dibuka), untuk: CA private key, code signing, payment processing, cryptocurrency exchange. Cloud HSM: AWS CloudHSM, Azure Dedicated HSM."}
],
14: [
  {"question":"Jika kamu merancang sistem embedded dengan constraint: MCU 32-bit, 256KB Flash, 32KB SRAM, baterai coin cell (CR2032), target operasional 10 tahun. Strategi yang PALING tepat adalah...","options":["Gunakan OS RTOS penuh dengan semua fitur","Gunakan bare-metal dengan event-driven architecture, agressively duty-cycle semua peripheral, gunakan kompresi data untuk Flash, dan ukur power consumption tiap peripheral secara individual","Gunakan WiFi untuk transmit data sesering mungkin","Optimasi hanya clock speed CPU saja"],"answer":1,"difficulty":3,"explanation":"10-year coin cell challenge: CR2032 ~230mAh. Target: ~26μA rata-rata untuk 10 tahun (30%+ margin). Strategy: (1) MCU sleep mode dominan (>99.9% waktu), wake hanya dari RTC interrupt; (2) ADC, radio, sensor: power only saat dibutuhkan; (3) Event-driven: tidak ada polling; (4) Data compression: HEATSHRINK/LZF untuk Flash efficiency; (5) Profiling: measure setiap peripheral, eliminasi yang tidak perlu. Nordic nRF52840 dengan mesh Bluetooth bisa <5μA rata-rata."},
  {"question":"Seorang insinyur ingin menjelaskan mengapa benchmark sintetis (seperti Cinebench, SPECcpu) tidak selalu mencerminkan performa aplikasi real-world. Alasan paling komprehensif adalah...","options":["Benchmark selalu di-manipulasi oleh vendor","Benchmark menggunakan workload spesifik yang mungkin tidak representatif dari code pattern, memory access pattern, dan working set size aplikasi nyata — CPU bisa di-optimasi khusus untuk benchmark","Benchmark hanya valid untuk PC gaming","Hardware terlalu baru untuk benchmark lama"],"answer":1,"difficulty":3,"explanation":"Benchmark validity issues: (1) Code pattern: SPECcpu2017 heavy floating-point, tapi enterprise app mostly integer; (2) Memory footprint: benchmark fit in cache, app nyata tidak; (3) I/O bound: benchmark CPU-bound saja; (4) Compiler-specific: auto-vectorization berbeda per compiler; (5) Vendor optimization: BLAS/MKL di-tune untuk hardware sendiri. Real performance: benchmark yang paling relevan adalah benchmark dengan workload Anda sendiri ('roll your own')."},
  {"question":"Mengapa 'dark silicon' menjadi masalah kritis dalam desain chip modern pasca-Dennard Scaling failure?","options":["Silicon gelap memiliki resistance lebih tinggi","Semakin banyak transistor yang harus dimatikan ('dark') pada waktu tertentu karena power budget tidak memungkinkan semua transistor aktif simultan — memaksa trade-off antara area, power, dan performa","Dark silicon adalah hasil dari proses fabrikasi yang buruk","Transistor di tepi chip tidak bisa digunakan karena noise"],"answer":1,"difficulty":3,"explanation":"Dark silicon (Esmaeilzadeh et al., 2011): pada 8nm node, hanya ~21% chip bisa aktif simultan dalam power budget normal. Implikasi: (1) Heterogeneous chip: matikan general cores, aktifkan specialized accelerator (GPU, DSP, ISP, NPU) sesuai workload; (2) Turbo boost: matikan beberapa core untuk naikkan voltase/clock satu core; (3) Domain-specific architecture: buat accelerator yang sangat efisien untuk workload spesifik. ARM big.LITTLE adalah respons langsung."},
  {"question":"Dalam desain prosesor, trade-off antara in-order vs out-of-order execution core untuk IoT edge inference adalah...","options":["Out-of-order selalu lebih baik dalam semua kondisi","In-order: lebih hemat daya dan area, deterministik, cukup untuk regular matrix computation dalam DNN inference; out-of-order: efisien untuk irregular access pattern tapi overhead hardware besar — untuk edge IoT, in-order NPU biasanya lebih optimal","In-order execution tidak bisa menjalankan neural network","Out-of-order execution gratis dalam hal power"],"answer":1,"difficulty":3,"explanation":"In-order pros untuk edge AI: (1) No ROB, no reservation stations, no physical register file overhead (area/power); (2) Neural network inference: pattern regular, data dependency dapat diprediksi compiler; (3) Deterministic execution time (critical untuk real-time). Apple Neural Engine, Google Edge TPU, Arm Ethos-N: semua in-order specialized untuk NN workload. Out-of-order overhead 30-50% area/power — tidak worth it untuk inference yang memory-bound bukan latency-bound."},
  {"question":"Cache coherency protocol yang paling scalable untuk 1000+ core system adalah...","options":["Snooping protocol karena paling sederhana","Directory-based protocol karena tidak memerlukan broadcast — setiap cache line punya directory entry yang melacak sharer list, sehingga invalidation hanya dikirim ke sharer yang relevan","MESI protocol selalu lebih efisien dari MOESI","Token coherency protocol tidak memerlukan directory"],"answer":1,"difficulty":3,"explanation":"Snooping tidak scalable: broadcast ke semua cache → bandwidth O(N²) dengan N prosesor. Directory protocol (Censier & Feautrier 1978): directory mencatat untuk setiap cache line: presence bit (sharer list) dan state. Read miss: directory kirim data + update sharer list. Write: directory invalidate hanya sharer yang ada di list. Bandwidth O(N) untuk most operations. Digunakan di: AMD EPYC (dengan Infinity Fabric directory), Intel Xeon scalable."},
  {"question":"Memory ordering bug (data race) antara dua thread adalah contoh dari...","options":["Stack overflow error","Heisenbugs — bug yang muncul/hilang tergantung timing, dan bisa tidak reproducible saat debugging (debugger mengubah timing)","Compile-time error yang compiler tidak deteksi","Logic error yang selalu reproducible"],"answer":1,"difficulty":3,"explanation":"Heisenbugs (Heisenberg uncertainty analogy): observasi mengubah behavior. Data race: Thread A write, Thread B read tanpa synchronization — result tergantung scheduling OS (non-deterministic). Di bawah debugger: context switch timing berubah → bug menghilang. Deteksi: ThreadSanitizer (TSan), Helgrind (Valgrind), Intel Inspector. Fix: mutex, atomic operations, atau immutable data + message passing."},
  {"question":"Seorang arsitektur chip ingin mendesain processor yang optimal untuk large language model (LLM) inference pada device (tidak di cloud). Pertimbangan paling kritis adalah...","options":["Memaksimalkan FLOPS/second sebesar mungkin","Memory bandwidth dan capacity adalah bottleneck utama — LLM weight (70B parameter = 140GB FP16) harus di-stream dari memory; DRAM bandwidth menentukan inference speed, bukan peak FLOPS","Frekuensi clock setinggi mungkin","Jumlah core CPU sebanyak mungkin"],"answer":1,"difficulty":3,"explanation":"LLM inference bottleneck analysis: untuk autoregressive generation (one token at a time), operasi adalah matrix-vector multiply (tidak matrix-matrix) → arithmetic intensity rendah (~O(1) FLOPs per byte). Ini memory bandwidth-bound, bukan compute-bound. Apple M3 Ultra (800GB/s unified memory bandwidth) jauh lebih baik untuk LLM inference dari PC dengan RTX 4090 (1 TB/s GDDR6X) karena: M3 bisa host 192GB model dalam unified memory vs GPU 24GB VRAM."},
  {"question":"RISC-V Vector Extension (RVV) berbeda dari ARM SVE dan x86 AVX dalam hal...","options":["RVV menggunakan instruksi lebih banyak dari ARM SVE","RVV menggunakan vector length agnostic (VLA) model — instruksi tidak hard-code lebar vector; hardware bisa implementasi lebar berbeda (128-bit hingga 65536-bit) dan software yang sama berjalan di semua","RVV tidak mendukung floating point operation","RVV hanya tersedia di embedded RISC-V"],"answer":1,"difficulty":3,"explanation":"AVX-512 (x86): hard-coded 512-bit register — software harus ditulis ulang untuk lebar berbeda. ARM SVE (Scalable Vector Extension): sama VLA approach seperti RVV. RVV VLA: VLEN (vector length) ditentukan hardware, software query dengan VSETVL. Kode yang sama berjalan optimal di: embedded RISC-V (VLEN=128) dan HPC RISC-V (VLEN=2048). Eliminasi fragmentation yang ada di SSE/AVX/AVX2/AVX-512 ecosystem."},
  {"question":"Mengapa desain ISA yang baik harus mempertimbangkan 'software ecosystem' bukan hanya hardware performance?","options":["Software ecosystem tidak relevan untuk hardware design","ISA yang superior secara teknis tapi tanpa software support (compiler, OS, library, application) tidak akan diadopsi — Intel IA-64 (Itanium) adalah contoh klasik kegagalan ISA karena compiler tidak bisa fully exploit VLIW complexity","ISA bisa diganti setiap tahun tanpa cost","Software bisa ditulis ulang dalam seminggu untuk ISA baru"],"answer":1,"difficulty":3,"explanation":"ISA lock-in: x86 bertahan bukan karena superioritas teknis tapi karena ecosystem (Windows, Office, semua aplikasi). Itanium failure: 2001-2017, meski secara teoritis superior (EPIC/VLIW), Intel dan compiler vendors tidak bisa menghasilkan kompiler yang cukup baik untuk exploit ILP yang di-expose. ARM success: started in embedded, slowly built ecosystem (Android/iOS), kini challenge x86 di server (AWS Graviton, Ampere Altra). RISC-V mengambil pelajaran ini — modular extension agar ecosystem tidak terfragmentasi."},
  {"question":"Ketika merancang sistem real-time dengan deadline kritis (misalnya kontrol fly-by-wire pada pesawat), mengapa out-of-order CPU dengan cache hierarchy yang kompleks TIDAK digunakan?","options":["Out-of-order CPU terlalu mahal untuk aerospace","Out-of-order execution dan cache menciptakan execution time yang tidak deterministik (Worst-Case Execution Time/WCET sangat sulit dibuktikan) — sistem safety-critical memerlukan guaranteed bounded response time","Cache terlalu kecil untuk program avionik","Arm menggunakan CISC untuk avionik"],"answer":1,"difficulty":3,"explanation":"Hard real-time systems (DO-178C certification): harus membuktikan WCET untuk setiap task. OoO CPU + cache: cache miss bisa menyebabkan 200-cycle latency, branch misprediction, memory speculation — membuat WCET analysis hampir impossible atau sangat konservatif. Solution: in-order CPU dengan scratchpad memory (deterministik), atau simple direct-mapped cache dengan WCET analysis tool (SWEET, OTAWA). Boeing 787 menggunakan Wind River VxWORKS pada PowerPC in-order."},
  {"question":"Storage Class Memory dalam hierarki memori masa depan (DRAM → SCM → NVMe) mengubah cara programmer menulis software karena...","options":["SCM tidak kompatibel dengan C/C++","SCM bersifat persistent dan byte-addressable, sehingga programmer harus secara eksplisit memastikan crash consistency — data di memori bisa bertahan power loss, memerlukan careful ordering dari store operations (crash-consistent data structures)","SCM menghapus kebutuhan database","SCM otomatis menjaga konsistensi data"],"answer":1,"difficulty":3,"explanation":"Traditional DRAM: volatile → semua data hilang saat crash, programmer tidak perlu pikir tentang partial writes. SCM (persistent): partial write sebelum crash menciptakan inconsistent state. PM programmer harus: (1) Gunakan CLWB+SFENCE untuk flush cache dan ordering; (2) Atomic 8-byte store (hardware guarantee); (3) Logging (undo/redo) atau copy-on-write untuk multi-word atomic update; (4) Crash-consistent library: PMDK (Intel), NVM.malloc. New programming model: PM-aware databases (pmem-Redis, pmem-RocksDB)."},
  {"question":"Pendekatan 'Chiplet + UCIe standard' yang dikembangkan Intel, AMD, ARM, TSMC, dan SAMSUNG bersama-sama bertujuan untuk...","options":["Menciptakan monopoli chiplet oleh satu vendor","Membuat chiplet interoperable antar vendor — die dari TSMC bisa connect ke die dari Samsung via standar UCIe (Universal Chiplet Interconnect Express), memungkinkan sistem integrasi chiplet dari multiple foundry dan IP vendor","Menggantikan PCIe sepenuhnya","Membuat chiplet yang kompatibel dengan DDR5"],"answer":1,"difficulty":3,"explanation":"UCIe (Universal Chiplet Interconnect Express, 2022): standar die-to-die interface. Physical: wire bonding, atau advanced packaging (flip-chip, CoWoS). Protocol: CXL dan PCIe di atas UCIe physical. Vision: marketplace chiplet — beli CPU core chiplet dari ARM, GPU compute chiplet dari AMD, memory controller chiplet dari Marvell, IO chiplet dari Intel — semua compatible. Analog ke PCIe yang memungkinkan GPU dari berbagai vendor di motherboard yang sama."},
  {"question":"Untuk aplikasi yang memerlukan akses acak ke dataset 10TB dengan latensi <100 microsecond, solusi storage yang paling tepat secara arsitektur adalah...","options":["10TB DRAM server (seluruhnya dalam memori)","Distributed NVMe SSD cluster dengan direct access protocol (SPDK/DPDK, NVMe-oF) — NVMe SSD random read ~70-100μs, distributed setup memberikan aggregate IOPS yang tinggi, jauh lebih cost-effective dari DRAM","HDD RAID 0 untuk bandwidth maksimal","Tape library dengan deduplication"],"answer":1,"difficulty":3,"explanation":"Latency comparison: DRAM ~80ns (ideal tapi $100K+ untuk 10TB), NVMe SSD ~70-100μs (10TB SSD ~$1000), HDD ~5-10ms (terlalu lambat untuk <100μs requirement). NVMe-oF (NVMe over Fabrics): akses NVMe SSD remote via RDMA (InfiniBand/RoCE) dengan added latency <10μs. SPDK (Storage Performance Dev Kit): bypass kernel untuk zero-copy NVMe access. Solusi: distributed NVMe cluster + NVMe-oF + DRAM cache untuk hot data."},
  {"question":"Kesimpulan apa yang bisa ditarik dari fakta bahwa hampir semua ISA modern (ARM, x86, RISC-V) berkonvergensi menuju fitur yang sama (out-of-order, speculative execution, large register file, SIMD)?","options":["Semua ISA pada akhirnya akan identik","Ada prinsip-prinsip arsitektur fundamental (ILP exploitation, memory hierarchy management, SIMD for data parallelism) yang independent dari ISA syntax — hardware yang efisien pada semua platform mengimplementasikan microarchitecture yang sama di bawah ISA yang berbeda","ARM dan x86 akan merge menjadi satu ISA","RISC-V tidak perlu feature ini karena lebih baru"],"answer":1,"difficulty":3,"explanation":"ISA vs Microarchitecture distinction: ISA = kontrak antara hardware dan software (apa yang bisa dilakukan). Microarchitecture = cara mengimplementasikan ISA secara efisien. Convergence: Intel (CISC RISC-like micro-ops), ARM (RISC tapi superscalar OoO), RISC-V (RISC dengan extensions). Semua butuh: branch predictor (control hazard), OoO (ILP), SIMD (data parallelism), large cache (memory wall). Pelajaran: microarchitecture optimization transcends ISA boundaries."},
  {"question":"Seorang developer menghadapi situasi: program memiliki throughput yang diharapkan tapi latency sangat tinggi dan inconsistent (high tail latency — P99 jauh di atas P50). Penyebab arsitektur yang paling mungkin adalah...","options":["CPU clock terlalu rendah","Cache miss yang tidak terprediksi, garbage collection pause, OS scheduling jitter, atau NUMA memory access yang tidak optimal — semua menyebabkan occasional long stall yang mempengaruhi tail latency tanpa mempengaruhi throughput secara signifikan","RAM terlalu sedikit","Program logic yang salah"],"answer":1,"difficulty":3,"explanation":"Tail latency challenge (Jeff Dean/Google): P50 (median) bagus tapi P99/P99.9 tinggi → 1% request sangat lambat. Root causes: (1) Cache miss yang rare tapi costly (200 cycle); (2) GC pause (Java stop-the-world, bisa 100ms+); (3) OS scheduling (preemption saat di critical path); (4) NUMA: remote memory access 3x lebih lambat; (5) Lock contention pada hot path. Solutions: NUMA-aware allocation, GC tuning (G1GC vs ZGC), CPU affinity pinning, lock-free data structures, real-time OS scheduling class."},
  {"question":"Dalam konteks performance engineering, 'Roofline Model' membantu menentukan...","options":["Berapa banyak core yang diperlukan aplikasi","Apakah aplikasi compute-bound atau memory-bandwidth-bound berdasarkan arithmetic intensity (FLOPs/byte) vs hardware peak — menentukan di mana optimasi paling efektif dilakukan","Ukuran cache yang optimal untuk aplikasi","Apakah perlu menambah RAM atau CPU"],"answer":1,"difficulty":3,"explanation":"Roofline model (Williams et al., 2009): plot log-log: x-axis = arithmetic intensity (FLOPs/byte of memory traffic), y-axis = attainable GFLOPs/s. Hardware memiliki dua batas: compute ceiling (peak FLOPS) dan memory roof (bandwidth × AI). Titik perpotонgan = ridge point. Jika AI < ridge point → memory-bandwidth bound (optimasi: reduce memory traffic, improve reuse). Jika AI > ridge point → compute bound (optimasi: increase ILP, vectorize). Digunakan di: Intel Advisor, NVIDIA Nsight."},
  {"question":"Evolusi dari single-core → multi-core → many-core → domain-specific accelerators mencerminkan respons industri terhadap...","options":["Tuntutan pasar untuk CPU yang lebih berwarna","Berakhirnya Dennard Scaling (tidak bisa naikkan frekuensi) dan melambatnya Moore's Law — industri mengejar performa via parallelism dan specialization alih-alih clock speed","Keterbatasan software yang tidak bisa gunakan core tunggal","Regulasi pemerintah yang membatasi frekuensi CPU"],"answer":1,"difficulty":3,"explanation":"Timeline: Pre-2004 (Dennard Scaling): clock speed naik, power tetap per area. 2004 (Power wall): frequency plateau ~3-4GHz. 2005-2015 (multi-core): parallelism menggantikan frequency scaling — tapi Amdahl membatasi. 2015-sekarang (specialization): GPU, TPU, NPU, DSP, ISP karena dark silicon — hanya spesialisasi yang bisa fully utilize power budget. Moore's Law melambat: 2nm = $15B+ fab investment. Era: chiplet, 3D stacking, heterogeneous SoC."},
  {"question":"Mengapa 'mechanical sympathy' adalah prinsip penting bagi software developer yang menulis high-performance system?","options":["Developer perlu mengetahui cara merakit komputer fisik","Understanding hardware architecture (cache line size, NUMA topology, branch prediction, false sharing) memungkinkan developer menulis software yang 'bekerja dengan hardware', bukan melawannya — menghasilkan perbedaan performa 10-100x","Mechanical sympathy hanya relevan untuk game developer","Hardware modern sudah otomatis mengoptimalkan semua kode"],"answer":1,"difficulty":3,"explanation":"Mechanical sympathy (Martin Thompson dari LMAX Disruptor): software yang sadar arsitektur hardware dapat jauh outperform software yang tidak. Examples: (1) Cache-friendly data layout (AoS vs SoA — 4x perbedaan); (2) False sharing avoidance (pad struct ke 64-byte cache line); (3) Branch-free code untuk predictable pipeline; (4) NUMA-aware allocation; (5) Lock-free ring buffer (Disruptor: 6M msg/s vs 700K msg/s dengan BlockingQueue). Knowledge tentang hardware → empowered developer."},
  {"question":"Ketika mengevaluasi processor baru untuk workload yang sangat spesifik, metrik yang paling relevan dibanding peak FLOPS adalah...","options":["Harga processor di pasaran","FLOPS yang benar-benar dicapai untuk workload spesifik (roofline analysis), energy efficiency (FLOPS/Watt), memory bandwidth, dan Total Cost of Ownership (TCO) — peak FLOPS adalah marketing number yang jarang dicapai","Jumlah core dan thread processor","Brand dan reputasi vendor"],"answer":1,"difficulty":3,"explanation":"Peak FLOPS fallacy: NVIDIA A100 = 312 TFLOPS FP16 (Tensor Core). Tapi LLM training efficiency: ~35-40% utilization (111-125 TFLOPS effective). Real metrics: (1) MFU (Model FLOP Utilization): actual FLOPS / theoretical peak; (2) FLOPS/$ (price efficiency); (3) FLOPS/Watt (energy efficiency); (4) Memory bandwidth (often true bottleneck); (5) TCO: hardware + power + cooling + space. Google TPU v4 wins on TCO untuk internal workload meski AMD/NVIDIA winning on paper spec."},
  {"question":"Prinsip 'make the common case fast' (Amdahl, Patterson & Hennessy) dalam desain arsitektur komputer berarti...","options":["Membuat operasi yang paling mahal menjadi murah","Mengoptimalkan jalur eksekusi yang paling sering terjadi (fast path) bahkan dengan mengorbankan kecepatan kasus yang jarang — impact terbesar pada performa keseluruhan ada di common case","Membuat semua kasus sama cepatnya","Menggunakan hardware khusus untuk semua kasus"],"answer":1,"difficulty":3,"explanation":"Common case fast examples: (1) Cache: common case = hit (95%+) harus sangat cepat, miss boleh lambat; (2) Branch predictor: common case = prediction correct (95%+), misprediction penalti diterima; (3) x86 decoder: simple instruksi (common) → fast path 1 cycle decode, kompleks → microcode; (4) OS: user mode (common) → fast, kernel mode → overhead diterima; (5) Memory allocator: small allocation (common) → O(1), large → O(log n). Tension: rare case tetap harus handled correctly."},
  {"question":"Dari semua konsep yang dipelajari dalam mata kuliah AOK, mengapa memahami trade-off adalah skill yang paling fundamental bagi computer engineer?","options":["Karena semua masalah computer engineering memiliki solusi optimal yang tunggal","Tidak ada solusi 'terbaik' yang universal — setiap keputusan desain (area vs speed, power vs performance, latency vs throughput, generality vs efficiency) adalah trade-off yang optimal hanya dalam konteks constraint spesifik dan workload target","Trade-off hanya relevan untuk hardware design, bukan software","Memahami trade-off hanya penting untuk manajer proyek"],"answer":1,"difficulty":3,"explanation":"Computer engineering is trade-off engineering: (1) Cache: small+fast vs large+slow; (2) OoO: higher IPC vs power/area/complexity; (3) CISC vs RISC: dense code vs simple decode; (4) Consistency model: strong (easy programming) vs weak (high performance); (5) Specialization: maximum efficiency vs inflexibility. The 'right' answer changes with: target workload, power budget, area constraint, time-to-market, cost. A great engineer asks: 'What are we optimizing for, and what are we willing to sacrifice?'"}
]
};

// ============================================================================
// PROSES PENGGABUNGAN KE QUIZZES.JSON
// ============================================================================

// 0. Masukkan Tambahan Level 1-5 (Gunakan Set untuk mencegah duplikasi karena L1-5 sudah ada data aslinya)
for (let lvl = 1; lvl <= 5; lvl++) {
  const levelObj = quizzes.levels.find(l => l.id === lvl);
  if (levelObj && NEW_QUESTIONS_L1_5[lvl]) {
    const existingQuestions = new Set(levelObj.questions.map(q => q.question));
    for (const q of NEW_QUESTIONS_L1_5[lvl]) {
      if (!existingQuestions.has(q.question)) {
        levelObj.questions.push(q);
      }
    }
  }
}

// 1. Masukkan Level 6-10 (Timpa secara absolut)
for (let lvl = 6; lvl <= 10; lvl++) {
  const levelObj = quizzes.levels.find(l => l.id === lvl);
  if (levelObj && NEW_QUESTIONS_L6_10[lvl]) {
    levelObj.questions = [...NEW_QUESTIONS_L6_10[lvl]];
  }
}

// 2. Masukkan Level 11-14 (Timpa secara absolut)
for (let lvl = 11; lvl <= 14; lvl++) {
  const levelObj = quizzes.levels.find(l => l.id === lvl);
  if (levelObj && NEW_QUESTIONS_L11_14[lvl]) {
    levelObj.questions = [...NEW_QUESTIONS_L11_14[lvl]];
  }
}

let totalQuestions = 0;
quizzes.levels.forEach(l => {
  totalQuestions += (l.questions ? l.questions.length : 0);
});

// 3. Tulis ulang ke quizzes.json
fs.writeFileSync(quizzesPath, JSON.stringify(quizzes, null, 2), 'utf8');

console.log('===============================================================');
console.log('✅ SUKSES! File berhasil disatukan.');
console.log('✅ Quizzes.json kini memiliki total ' + totalQuestions + ' soal (L6-L14).');
console.log('✅ Anda kini bisa menghapus file update_quizzes.js dan update_quizzes_l6_10.js');
console.log('===============================================================');
